// Computer Networks — 150 Questions
export const CN_Q = [
  { id: "cn1", diff: "easy", topic: "OSI Model", q: "How many layers does the OSI model have?", opts: ["5", "6", "7", "8"], ans: 2, exp: "The OSI model has exactly 7 layers: Physical, Data Link, Network, Transport, Session, Presentation, and Application â€” each with distinct responsibilities." },
  { id: "cn2", diff: "easy", topic: "OSI Model", q: "Which OSI layer is responsible for end-to-end communication and error recovery?", opts: ["Network Layer", "Transport Layer", "Session Layer", "Data Link Layer"], ans: 1, exp: "The Transport layer (Layer 4) ensures reliable, end-to-end delivery via error detection, retransmission, and flow control. TCP and UDP operate here." },
  { id: "cn3", diff: "easy", topic: "OSI Model", q: "At which OSI layer do routers primarily operate?", opts: ["Data Link (Layer 2)", "Network (Layer 3)", "Transport (Layer 4)", "Physical (Layer 1)"], ans: 1, exp: "Routers operate at Layer 3 (Network), reading IP headers to make forwarding decisions. They strip and rebuild Layer 2 frames at each hop." },
  { id: "cn4", diff: "easy", topic: "OSI Model", q: "Which layer converts data into bits for transmission over a physical medium?", opts: ["Data Link", "Presentation", "Physical", "Session"], ans: 2, exp: "The Physical layer (Layer 1) handles raw bit transmission â€” voltages, frequencies, cables, and connectors. It has no understanding of frames or packets." },
  { id: "cn5", diff: "easy", topic: "OSI Model", q: "Encryption and data compression are functions of which OSI layer?", opts: ["Session Layer", "Transport Layer", "Presentation Layer", "Application Layer"], ans: 2, exp: "The Presentation layer (Layer 6) handles data formatting, encryption, and compression so the receiving application can understand it regardless of platform." },
  { id: "cn6", diff: "easy", topic: "OSI Model", q: "What is the PDU at the Transport layer called?", opts: ["Frame", "Packet", "Segment", "Bit"], ans: 2, exp: "PDUs by layer â€” Physical: Bit, Data Link: Frame, Network: Packet, Transport: Segment, Application: Data." },
  { id: "cn7", diff: "easy", topic: "OSI Model", q: "Which OSI layer establishes, manages, and terminates sessions between applications?", opts: ["Transport", "Presentation", "Session", "Network"], ans: 2, exp: "The Session layer (Layer 5) manages dialogues â€” it sets up, coordinates, and terminates conversations between applications on different hosts." },
  { id: "cn8", diff: "easy", topic: "OSI Model", q: "Switches primarily operate at which OSI layer?", opts: ["Physical Layer", "Network Layer", "Data Link Layer", "Transport Layer"], ans: 2, exp: "Switches use MAC addresses at Layer 2 (Data Link) to make forwarding decisions. Layer 3 switches also perform routing." },
  { id: "cn9", diff: "easy", topic: "TCP/IP", q: "How many layers does the TCP/IP model have?", opts: ["4", "5", "6", "7"], ans: 0, exp: "TCP/IP has 4 layers: Network Access (Link), Internet, Transport, and Application. The Application layer maps to OSI's Session+Presentation+Application." },
  { id: "cn10", diff: "easy", topic: "TCP/IP", q: "Which protocol provides reliable, connection-oriented data delivery?", opts: ["UDP", "ICMP", "TCP", "ARP"], ans: 2, exp: "TCP is connection-oriented â€” it uses a 3-way handshake, sequence numbers, ACKs, and retransmissions to guarantee delivery." },
  { id: "cn11", diff: "easy", topic: "TCP/IP", q: "Which protocol is connectionless and provides no delivery guarantee?", opts: ["TCP", "UDP", "FTP", "SMTP"], ans: 1, exp: "UDP is connectionless with no handshake, ACKs, or retransmission â€” fast and ideal for real-time apps like DNS, VoIP, and video streaming." },
  { id: "cn12", diff: "easy", topic: "TCP/IP", q: "In the TCP three-way handshake, what is the correct sequence?", opts: ["SYN â†’ ACK â†’ SYN-ACK", "SYN â†’ SYN-ACK â†’ ACK", "ACK â†’ SYN â†’ SYN-ACK", "SYN-ACK â†’ SYN â†’ ACK"], ans: 1, exp: "Client sends SYN â†’ Server replies SYN-ACK â†’ Client confirms with ACK. Only after this full exchange is a reliable TCP connection established." },
  { id: "cn13", diff: "easy", topic: "TCP/IP", q: "Which field in the IP header identifies whether TCP or UDP is the payload?", opts: ["TTL", "Checksum", "Protocol", "Flags"], ans: 2, exp: "The Protocol field carries a number identifying the transport layer: 6 = TCP, 17 = UDP, 1 = ICMP." },
  { id: "cn14", diff: "easy", topic: "TCP/IP", q: "What does IP fragmentation accomplish?", opts: ["Encrypts packets", "Splits packets exceeding the MTU into smaller fragments", "Reassembles frames at the Data Link layer", "Routes packets faster"], ans: 1, exp: "When a packet's size exceeds the MTU (e.g., 1500 bytes on Ethernet), the IP layer fragments it. Fragments are reassembled only at the final destination." },
  { id: "cn15", diff: "easy", topic: "TCP/IP", q: "Which ICMP message is sent when a router cannot forward a packet?", opts: ["Echo Request", "Echo Reply", "Destination Unreachable", "Time Exceeded"], ans: 2, exp: "ICMP Destination Unreachable is sent by a router when it cannot deliver a packet â€” due to no route, blocked port, or host being down." },
  { id: "cn16", diff: "easy", topic: "Protocols", q: "What port does HTTP use by default?", opts: ["21", "23", "80", "443"], ans: 2, exp: "HTTP = port 80. HTTPS = 443. FTP = 21. Telnet = 23. SSH = 22. These port numbers are essential placement knowledge." },
  { id: "cn17", diff: "easy", topic: "Protocols", q: "What port does HTTPS use?", opts: ["80", "8080", "443", "22"], ans: 2, exp: "HTTPS uses port 443. It wraps HTTP inside a TLS tunnel, providing encryption, authentication, and integrity." },
  { id: "cn18", diff: "easy", topic: "Protocols", q: "Which protocol resolves IP addresses to MAC addresses?", opts: ["DNS", "RARP", "ARP", "DHCP"], ans: 2, exp: "ARP broadcasts 'Who has IP x.x.x.x?' on the local LAN. The owner replies with its MAC address, which is cached locally." },
  { id: "cn19", diff: "easy", topic: "Protocols", q: "Which protocol automatically assigns IP addresses to hosts?", opts: ["DNS", "ARP", "DHCP", "NAT"], ans: 2, exp: "DHCP uses a 4-step DORA process: Discover â†’ Offer â†’ Request â†’ Acknowledge, assigning IPs from a pool." },
  { id: "cn20", diff: "easy", topic: "Protocols", q: "DNS resolves which of the following?", opts: ["IP address to MAC address", "MAC address to IP address", "Domain name to IP address", "IP address to Domain name"], ans: 2, exp: "DNS translates human-friendly domain names (www.google.com) into machine-routable IP addresses." },
  { id: "cn21", diff: "easy", topic: "Protocols", q: "Which protocol is used to SEND email?", opts: ["IMAP", "POP3", "SMTP", "FTP"], ans: 2, exp: "SMTP on port 25 (or 587 for submission) sends mail between servers and from clients to servers. IMAP/POP3 are for receiving." },
  { id: "cn22", diff: "easy", topic: "Protocols", q: "Which protocol is used to securely access a remote machine via CLI?", opts: ["Telnet", "FTP", "SSH", "SNMP"], ans: 2, exp: "SSH on port 22 encrypts the entire session. Telnet (port 23) sends everything in plaintext â€” a security risk." },
  { id: "cn23", diff: "easy", topic: "Protocols", q: "Ping uses which protocol internally?", opts: ["TCP", "UDP", "ICMP", "ARP"], ans: 2, exp: "Ping uses ICMP Echo Request (type 8) and Echo Reply (type 0). It measures round-trip time and packet loss." },
  { id: "cn24", diff: "easy", topic: "Protocols", q: "Which protocol is used for network management and monitoring of devices?", opts: ["SNMP", "SMTP", "SIP", "SOAP"], ans: 0, exp: "SNMP on UDP port 161 is used to monitor routers, switches, and servers. MIBs define the variables that can be queried." },
  { id: "cn25", diff: "easy", topic: "Protocols", q: "Which protocol retrieves email while keeping messages on the server?", opts: ["SMTP", "POP3", "IMAP", "FTP"], ans: 2, exp: "IMAP (port 143/993 with SSL) syncs email with the server â€” messages stay there. POP3 (port 110) downloads and typically deletes them." },
  { id: "cn26", diff: "easy", topic: "Protocols", q: "What does NAT stand for?", opts: ["Network Address Translation", "Network Access Terminal", "Node Address Table", "Network Aggregation Technique"], ans: 0, exp: "NAT allows multiple devices with private IPs (RFC 1918) to share one public IP by modifying IP/port headers in packets." },
  { id: "cn27", diff: "easy", topic: "Protocols", q: "FTP stands for?", opts: ["Fast Transfer Protocol", "File Transfer Protocol", "Frame Transfer Protocol", "Forwarding Transfer Protocol"], ans: 1, exp: "FTP uses TCP port 21 for control and port 20 for data. SFTP (over SSH) and FTPS (over TLS) are the secure alternatives." },
  { id: "cn28", diff: "easy", topic: "Protocols", q: "Which protocol synchronizes time across network devices?", opts: ["SNMP", "NTP", "LDAP", "RADIUS"], ans: 1, exp: "NTP (UDP port 123) synchronizes clocks. Accurate time is critical for log correlation, Kerberos authentication, and TLS certificate validation." },
  { id: "cn29", diff: "easy", topic: "Routing", q: "Which device connects multiple networks and forwards packets based on IP addresses?", opts: ["Hub", "Switch", "Router", "Bridge"], ans: 2, exp: "A router operates at Layer 3, reading IP headers to forward packets between networks. It maintains a routing table and supports protocols like OSPF, BGP, RIP." },
  { id: "cn30", diff: "easy", topic: "Routing", q: "What does TTL stand for in IP packets?", opts: ["Transfer Time Limit", "Time To Live", "Total Traffic Load", "Transmission Type Level"], ans: 1, exp: "TTL is decremented by 1 at each router hop. When it reaches 0, the packet is dropped and an ICMP Time Exceeded message is sent back â€” preventing infinite loops." },
  { id: "cn31", diff: "easy", topic: "Routing", q: "What is a default gateway?", opts: ["A server that assigns IPs", "The router IP used to reach external networks", "A firewall configuration", "A reserved IP for broadcast"], ans: 1, exp: "The default gateway is the next-hop router IP that a host uses for traffic destined outside its local subnet. Without it, hosts cannot communicate beyond their LAN." },
  { id: "cn32", diff: "easy", topic: "Routing", q: "What is a routing table used for?", opts: ["Store MAC addresses", "Store user passwords", "Determine the best path to forward packets", "Log all network traffic"], ans: 2, exp: "A routing table stores destination networks, next-hop addresses, and outgoing interfaces. Routers consult it for every packet, selecting the longest prefix match." },
  { id: "cn33", diff: "easy", topic: "Switching", q: "What is the main advantage of a switch over a hub?", opts: ["Switch is cheaper", "Switch broadcasts to all ports", "Switch forwards data only to the destination port", "Switch works at Layer 3"], ans: 2, exp: "A hub blindly broadcasts to all ports (creating collisions). A switch learns MAC addresses and forwards frames only to the correct port." },
  { id: "cn34", diff: "easy", topic: "Switching", q: "What is a VLAN?", opts: ["A type of physical cable", "A virtual private network", "A logical grouping of devices regardless of physical location", "A routing protocol"], ans: 2, exp: "A VLAN segments a physical switch into multiple logical networks, reducing broadcast domains, improving security, and enabling traffic isolation." },
  { id: "cn35", diff: "easy", topic: "Switching", q: "What does CSMA/CD stand for?", opts: ["Carrier Sense Multiple Access / Collision Detection", "Carrier Signal Multiple Access / Collision Delay", "Channel Sense Multiple Access / Collision Detection", "Carrier Sense Media Access / Carrier Detection"], ans: 0, exp: "CSMA/CD is Ethernet's collision handling: sense the carrier before sending; if a collision is detected, stop, wait a random backoff, then retry." },
  { id: "cn36", diff: "easy", topic: "Subnetting", q: "What is the default subnet mask for a Class C IP address?", opts: ["255.0.0.0", "255.255.0.0", "255.255.255.0", "255.255.255.255"], ans: 2, exp: "Class C: /24 = 255.255.255.0, supporting 254 usable hosts. Class B: /16 = 255.255.0.0. Class A: /8 = 255.0.0.0." },
  { id: "cn37", diff: "easy", topic: "Subnetting", q: "How many bits are in an IPv4 address?", opts: ["16", "32", "64", "128"], ans: 1, exp: "IPv4 = 32 bits, written as 4 octets in dotted decimal (e.g., 192.168.1.1). IPv6 = 128 bits, written in hexadecimal groups." },
  { id: "cn38", diff: "easy", topic: "Subnetting", q: "How many bits are in an IPv6 address?", opts: ["32", "64", "128", "256"], ans: 2, exp: "IPv6 = 128 bits, written as 8 groups of 4 hex digits separated by colons. It provides 2^128 addresses." },
  { id: "cn39", diff: "easy", topic: "Subnetting", q: "What is the broadcast address for the subnet 192.168.1.0/24?", opts: ["192.168.1.0", "192.168.1.1", "192.168.1.254", "192.168.1.255"], ans: 3, exp: "In a /24: .0 = network address, .255 = broadcast (sent to all hosts). Usable range: .1 to .254 = 254 hosts." },
  { id: "cn40", diff: "easy", topic: "Subnetting", q: "Which IP address range is reserved for loopback testing?", opts: ["10.0.0.0/8", "127.0.0.0/8", "192.168.0.0/16", "172.16.0.0/12"], ans: 1, exp: "127.0.0.0/8 is the loopback range. 127.0.0.1 ('localhost') tests the host's own TCP/IP stack without sending traffic." },
  { id: "cn41", diff: "easy", topic: "Subnetting", q: "A Class A IP address has how many bits for the host portion by default?", opts: ["8", "16", "24", "28"], ans: 2, exp: "Class A: 8 network bits + 24 host bits = 2^24 - 2 = 16,777,214 usable hosts per network." },
  { id: "cn42", diff: "easy", topic: "Data Link", q: "What is the purpose of a MAC address?", opts: ["Identify a network globally", "Identify a device on the internet", "Identify a device on a local network segment", "Assign IP addresses dynamically"], ans: 2, exp: "MAC addresses are 48-bit hardware addresses that uniquely identify devices on a local network segment. They operate at Layer 2 and are not routable." },
  { id: "cn43", diff: "easy", topic: "Data Link", q: "What is the size of a MAC address?", opts: ["32 bits", "48 bits", "64 bits", "128 bits"], ans: 1, exp: "MAC addresses are 48 bits (6 bytes), written as XX:XX:XX:XX:XX:XX in hex. The first 3 bytes = OUI (manufacturer), last 3 = device-specific." },
  { id: "cn44", diff: "easy", topic: "Data Link", q: "What does 802.11 refer to?", opts: ["Ethernet standard", "Wi-Fi (wireless LAN) standard", "Bluetooth standard", "Token Ring standard"], ans: 1, exp: "IEEE 802.11 defines Wi-Fi standards: 802.11a/b/g/n/ac/ax (Wi-Fi 6)/be (Wi-Fi 7). 802.3 = Ethernet, 802.1Q = VLAN tagging." },
  { id: "cn45", diff: "easy", topic: "Security", q: "What does a firewall primarily do?", opts: ["Speeds up network traffic", "Assigns IP addresses to hosts", "Filters incoming and outgoing traffic based on security rules", "Converts domain names to IP addresses"], ans: 2, exp: "A firewall enforces a security policy by permitting or blocking traffic based on rules (IP, port, protocol, state)." },
  { id: "cn46", diff: "easy", topic: "Security", q: "What is the purpose of SSL/TLS?", opts: ["Assign IP addresses", "Encrypt data in transit between client and server", "Filter network packets", "Compress data for faster transmission"], ans: 1, exp: "TLS provides encryption (confidentiality), authentication (server identity via certificates), and integrity (MAC). It replaced the deprecated SSL." },
  { id: "cn47", diff: "easy", topic: "Security", q: "What type of encryption uses one shared key for both encryption and decryption?", opts: ["Asymmetric encryption", "Symmetric encryption", "Hashing", "Public key cryptography"], ans: 1, exp: "Symmetric encryption (e.g., AES-256) uses one shared key â€” very fast for bulk data but requires secure key exchange." },
  { id: "cn48", diff: "easy", topic: "App Layer", q: "Which protocol does a web browser use to fetch web pages?", opts: ["FTP", "SMTP", "HTTP or HTTPS", "DNS"], ans: 2, exp: "Browsers use HTTP (port 80) for plain text and HTTPS (port 443, HTTP over TLS) for encrypted web traffic." },
  { id: "cn49", diff: "easy", topic: "App Layer", q: "What is traceroute used for?", opts: ["Test DNS resolution", "Map the route packets take to a destination, showing each hop", "Test firewall rules", "Measure download speed"], ans: 1, exp: "Traceroute sends packets with incrementing TTL values. Each router that decrements TTL to 0 sends back an ICMP Time Exceeded, revealing its IP and RTT." },
  { id: "cn50", diff: "easy", topic: "App Layer", q: "Which OSI layers does the TCP/IP Application layer combine?", opts: ["Only Application (Layer 7)", "Application and Transport", "Session (5), Presentation (6), and Application (7)", "Network and Transport"], ans: 2, exp: "TCP/IP's Application layer is a superset of OSI's top three layers: Session (5), Presentation (6), and Application (7)." },
  { id: "cn51", diff: "medium", topic: "Subnetting", q: "You have 192.168.10.0/28. How many usable host addresses are available?", opts: ["14", "16", "30", "254"], ans: 0, exp: "/28 means 4 host bits â†’ 2â´ = 16 total addresses. Subtract 2 (network address + broadcast) = 14 usable host addresses." },
  { id: "cn52", diff: "medium", topic: "Subnetting", q: "A company needs 5 subnets each supporting at least 25 hosts from 192.168.1.0/24. Most efficient mask?", opts: ["/25 (126 hosts)", "/26 (62 hosts)", "/27 (30 hosts)", "/28 (14 hosts)"], ans: 2, exp: "/27 gives 32 addresses per subnet (30 usable) â€” sufficient for 25 hosts. You get 8 such subnets from a /24." },
  { id: "cn53", diff: "medium", topic: "Subnetting", q: "How many /26 subnets can be created from a /24 network?", opts: ["2", "4", "8", "16"], ans: 1, exp: "/26 borrows 2 bits from /24: 2Â² = 4 subnets. Each /26 has 64 addresses (62 usable)." },
  { id: "cn54", diff: "medium", topic: "Subnetting", q: "What is VLSM and what problem does it solve?", opts: ["Variable Length Security Mask", "Variable Length Subnet Masking â€” allows subnets of different sizes, reducing IP waste", "Virtual LAN Security Model", "Variable Latency Speed Measurement"], ans: 1, exp: "VLSM lets you carve subnets of different sizes from one block â€” /30 for point-to-point links, /24 for large LANs. Prevents address waste." },
  { id: "cn55", diff: "medium", topic: "Subnetting", q: "What is CIDR and why was it introduced?", opts: ["A routing protocol to replace OSPF", "Classless Inter-Domain Routing â€” flexible prefix lengths to slow IPv4 exhaustion and enable route aggregation", "A protocol for dynamic IP assignment", "A security standard for routers"], ans: 1, exp: "CIDR (RFC 1519) abolished the rigid Class A/B/C system, allowing any prefix length. This enabled route aggregation, shrinking routing tables and conserving IPv4 space." },
  { id: "cn56", diff: "medium", topic: "Subnetting", q: "Which subnet mask minimizes IP waste on a point-to-point WAN link?", opts: ["/28 (14 usable)", "/29 (6 usable)", "/30 (2 usable)", "/31 or /30 depending on RFC support"], ans: 3, exp: "/30 gives exactly 2 usable hosts. RFC 3021 allows /31 (treating both as host addresses), which is even more efficient for point-to-point." },
  { id: "cn57", diff: "medium", topic: "Routing", q: "What is the key difference between static and dynamic routing?", opts: ["Static is always faster than dynamic", "Static routes are manually configured; dynamic routes are learned automatically via protocols like OSPF or BGP", "Static routing uses more bandwidth", "Dynamic routing always requires more CPU"], ans: 1, exp: "Static routes: manually entered, no overhead, no adaptability. Dynamic routing (OSPF, BGP, RIP) automatically discovers and adapts to topology changes." },
  { id: "cn58", diff: "medium", topic: "Routing", q: "RIP uses which metric to determine the best path?", opts: ["Bandwidth", "Hop count", "Delay", "Cost (inverse bandwidth)"], ans: 1, exp: "RIP uses hop count (max 15; 16 = infinite/unreachable). Its simplicity is also its weakness â€” it may choose a slower, lower-hop path over a faster, higher-hop one." },
  { id: "cn59", diff: "medium", topic: "Routing", q: "OSPF is classified as which type of routing protocol?", opts: ["Distance vector", "Link state", "Path vector", "Hybrid (advanced distance vector)"], ans: 1, exp: "OSPF is a link-state protocol. Every router floods LSAs, builds an identical LSDB, and runs Dijkstra's SPF algorithm to compute the shortest path tree." },
  { id: "cn60", diff: "medium", topic: "Routing", q: "BGP is primarily used for which purpose?", opts: ["Routing within a company LAN", "Routing between autonomous systems (ASes) on the internet", "Dynamically assigning IP addresses", "Encrypting routing update information"], ans: 1, exp: "BGP is the internet's routing protocol, exchanging reachability between ASes. It is a path-vector protocol, using AS_PATH to prevent loops." },
  { id: "cn61", diff: "medium", topic: "Routing", q: "What problem does split horizon solve in distance-vector routing?", opts: ["Routing loops between neighbors", "High CPU usage on routers", "Slow convergence only", "Packet fragmentation"], ans: 0, exp: "Split horizon: never advertise a route back out the interface you learned it from. This prevents the most common two-node routing loop." },
  { id: "cn62", diff: "medium", topic: "Routing", q: "A packet for 10.1.5.0/24 arrives at a router with routes 10.0.0.0/8 and 10.1.0.0/16. Which is chosen?", opts: ["10.0.0.0/8 â€” more general", "10.1.0.0/16 â€” longest prefix match", "Both are used via load balancing", "The packet is dropped"], ans: 1, exp: "Longest Prefix Match (LPM): the most specific matching route wins. /16 is more specific than /8." },
  { id: "cn63", diff: "medium", topic: "Routing", q: "What is administrative distance (AD) in routing?", opts: ["The physical cable distance between two routers", "A value ranking the trustworthiness of different routing sources", "The maximum hop count permitted", "The available bandwidth on a link"], ans: 1, exp: "AD is used when multiple protocols advertise a route to the same destination. Lower AD = more trusted. Connected=0, Static=1, EIGRP=90, OSPF=110, RIP=120." },
  { id: "cn64", diff: "medium", topic: "Routing", q: "What is route summarization (aggregation)?", opts: ["Splitting one network into many smaller subnets", "Combining multiple specific routes into a single summarized advertisement", "Encrypting routing protocol updates", "Prioritizing certain routes over others"], ans: 1, exp: "Route summarization (e.g., advertising 192.168.0.0/22 instead of four /24s) reduces routing table size, decreases update traffic, and hides internal topology." },
  { id: "cn65", diff: "medium", topic: "Routing", q: "EIGRP uses which combination of metrics?", opts: ["Hop count only", "Bandwidth and delay (primarily), plus optional load and reliability", "Cost based on interface speed only", "Hop count and reliability combined"], ans: 1, exp: "EIGRP's composite metric = K1Ã—bandwidth + K3Ã—delay (by default). It uses the DUAL algorithm, guaranteeing loop-free paths." },
  { id: "cn66", diff: "medium", topic: "Routing", q: "What is a null/blackhole route and when is it used?", opts: ["A backup route activated when the primary fails", "Discards packets for a specific prefix â€” used to prevent routing loops with summary routes or block traffic", "Routes packets through a VPN tunnel", "A static route with the highest possible metric"], ans: 1, exp: "A null route (e.g., 'ip route 10.0.0.0 255.0.0.0 Null0') discards matching packets. Used with route summarization to prevent loops." },
  { id: "cn67", diff: "medium", topic: "Switching", q: "What is the purpose of Spanning Tree Protocol (STP)?", opts: ["Assign IP addresses to switches automatically", "Prevent broadcast storms by eliminating Layer 2 forwarding loops", "Encrypt traffic between VLANs on trunk links", "Balance traffic load across multiple uplinks simultaneously"], ans: 1, exp: "Without STP, redundant switch paths would cause broadcast frames to loop endlessly (broadcast storm). STP elects a Root Bridge and blocks redundant ports." },
  { id: "cn68", diff: "medium", topic: "Switching", q: "In STP, what determines the Root Bridge election?", opts: ["The switch with the highest MAC address", "The switch with the lowest Bridge ID (Priority + MAC address)", "The switch closest to the internet gateway", "The switch with the most active ports"], ans: 1, exp: "Root Bridge = lowest Bridge Priority (default 32768) + MAC as tiebreaker. Manually set a lower priority (e.g., 4096) on the intended root." },
  { id: "cn69", diff: "medium", topic: "Switching", q: "What is MAC flooding and what vulnerability does it exploit?", opts: ["Flooding MAC address updates to all connected VLANs", "Overflowing the switch's CAM table with fake MACs, causing it to broadcast all traffic like a hub", "Sending oversized frames to cause a switch buffer overflow", "Spoofing multiple MAC addresses to monopolize switch bandwidth"], ans: 1, exp: "Switch CAM tables have finite size. MAC flooding fills it with fake entries, forcing the switch into fail-open mode (broadcasts everything). Port Security mitigates it." },
  { id: "cn70", diff: "medium", topic: "Switching", q: "What is the difference between an access port and a trunk port?", opts: ["Access ports carry multiple VLANs; trunk ports carry a single VLAN", "Access ports carry traffic for one VLAN; trunk ports carry multiple VLANs using 802.1Q tagging", "Access ports connect to routers; trunk ports connect to end devices", "Trunk ports are simply faster versions of access ports"], ans: 1, exp: "Access ports connect end devices to a single VLAN (untagged traffic). Trunk ports connect switches/routers and carry multiple VLANs using 802.1Q 4-byte tags." },
  { id: "cn71", diff: "medium", topic: "Switching", q: "What is proxy ARP and when is it useful?", opts: ["ARP that hides the real MAC address for security", "A router replies to ARP requests for remote hosts with its own MAC, enabling hosts without a default gateway to reach other subnets", "A broadcast ARP sent simultaneously to all subnets", "ARP used exclusively in wireless networks"], ans: 1, exp: "With Proxy ARP, a router responds to ARP for IPs it can reach, substituting its own MAC. Useful for hosts misconfigured without a gateway." },
  { id: "cn72", diff: "medium", topic: "Switching", q: "What is BPDU Guard and why is it configured on access ports?", opts: ["Speeds up STP convergence on trunk links", "Shuts down a port immediately if a BPDU is received â€” preventing rogue switches from altering the STP topology", "Prevents CAM table flooding on access ports", "A VLAN security mechanism for tagging frames"], ans: 1, exp: "PortFast + BPDU Guard: PortFast skips STP listening/learning states. If a BPDU is then received, BPDU Guard puts the port in err-disabled immediately." },
  { id: "cn73", diff: "medium", topic: "Protocols", q: "Which DNS record type maps a domain name to an IPv4 address?", opts: ["MX record", "CNAME record", "A record", "AAAA record"], ans: 2, exp: "A record = domain â†’ IPv4. AAAA = domain â†’ IPv6. MX = mail server. CNAME = alias pointing to another domain. NS = authoritative name servers." },
  { id: "cn74", diff: "medium", topic: "Protocols", q: "Which transport protocol do DNS queries typically use and why?", opts: ["TCP â€” for guaranteed delivery", "UDP â€” for low overhead and fast responses", "TCP â€” because DNS records are large", "Both TCP and UDP always used simultaneously"], ans: 1, exp: "DNS uses UDP port 53 for queries (fast, low overhead). TCP port 53 is used for zone transfers (AXFR) and responses exceeding 512 bytes (or 4096 with EDNS0)." },
  { id: "cn75", diff: "medium", topic: "Protocols", q: "What is the role of RADIUS in a network?", opts: ["Resolve DNS queries for network devices", "Provide centralized Authentication, Authorization, and Accounting (AAA)", "Translate private IP addresses to public ones", "Monitor and measure available bandwidth"], ans: 1, exp: "RADIUS (UDP 1812/1813) provides centralized AAA for network access. Used with 802.1X for Wi-Fi/wired authentication and VPN access." },
  { id: "cn76", diff: "medium", topic: "Protocols", q: "What is the purpose of DSCP (Differentiated Services Code Point) in the IP header?", opts: ["Identify the encapsulated transport protocol", "Mark packets with QoS class information so routers can prioritize traffic", "Fragment large packets before routing", "Detect and report routing loops to the sender"], ans: 1, exp: "DSCP (6 bits in the IP ToS field) marks packets with traffic class (e.g., EF for VoIP, AF41 for video). QoS-enabled routers use this to prioritize traffic." },
  { id: "cn77", diff: "medium", topic: "Protocols", q: "What protocol does VoIP primarily use for call signaling?", opts: ["HTTP", "SIP (Session Initiation Protocol)", "SMTP", "FTP"], ans: 1, exp: "SIP handles VoIP signaling â€” setting up, modifying, and terminating calls. RTP (Real-time Transport Protocol) carries the actual audio/video media stream." },
  { id: "cn78", diff: "medium", topic: "Protocols", q: "A web application uses WebSockets. What distinguishes them from HTTP?", opts: ["WebSockets use UDP for faster delivery", "WebSockets maintain a persistent full-duplex connection after an initial HTTP upgrade handshake", "WebSockets automatically encrypt all data by default", "WebSockets cannot be used over HTTPS connections"], ans: 1, exp: "WebSockets start with an HTTP 101 Upgrade request. Once upgraded, a persistent full-duplex TCP channel is open â€” both sides can send data anytime." },
  { id: "cn79", diff: "medium", topic: "Congestion", q: "Which TCP mechanism prevents overwhelming the network during connection startup?", opts: ["Fast Retransmit", "Slow Start", "Receiver-side Flow Control", "Sliding Window Protocol"], ans: 1, exp: "Slow Start begins with cwnd=1 MSS, doubling each RTT until ssthresh is reached, then switching to Congestion Avoidance (linear growth). It probes capacity cautiously." },
  { id: "cn80", diff: "medium", topic: "Congestion", q: "What happens to the TCP congestion window when triple duplicate ACKs are detected?", opts: ["cwnd is set to 0 and connection resets", "ssthresh = cwnd/2 and cwnd = ssthresh (Fast Recovery â€” not full Slow Start)", "cwnd is immediately reset to 1 MSS", "cwnd doubles to recover lost throughput"], ans: 1, exp: "Triple dup ACKs signal a single loss. Fast Retransmit resends the segment; Fast Recovery sets ssthresh=cwnd/2 and cwnd=ssthresh â€” avoiding expensive full Slow Start restart." },
  { id: "cn81", diff: "medium", topic: "Congestion", q: "What is the significance of ssthresh (slow start threshold) in TCP?", opts: ["It represents the maximum allowed window size", "It marks where TCP transitions from exponential (Slow Start) to linear (Congestion Avoidance) growth", "It defines the minimum RTT before backoff begins", "It equals the receiver's advertised buffer size"], ans: 1, exp: "Below ssthresh: cwnd doubles each RTT (Slow Start). At ssthresh: cwnd grows by 1 MSS per RTT (Congestion Avoidance)." },
  { id: "cn82", diff: "medium", topic: "Congestion", q: "What is ECN (Explicit Congestion Notification) and how does it improve on packet drops?", opts: ["A routing protocol that reroutes around congested links", "Routers mark packets (CE bit) instead of dropping them to signal congestion; the receiver echoes this to the sender to reduce rate without loss", "ECN increases the sender's cwnd when congestion is detected", "ECN is a firewall mechanism that rate-limits specific traffic flows"], ans: 1, exp: "Traditional congestion is signaled by packet drops. ECN sets the CE bit in the IP header; the receiver echoes it via TCP's ECE/CWR flags; the sender backs off without a retransmission event." },
  { id: "cn83", diff: "medium", topic: "Congestion", q: "What is the primary difference between flow control and congestion control in TCP?", opts: ["They are the same mechanism with different names", "Flow control prevents overwhelming the receiver (using receiver window); congestion control prevents overwhelming the network (using cwnd)", "Congestion control operates at Layer 2; flow control at Layer 4", "Flow control only works with UDP; congestion control is TCP-specific"], ans: 1, exp: "Flow control: receiver advertises its buffer size (rwnd); sender respects it. Congestion control: sender estimates network capacity via cwnd. Effective send rate = min(cwnd, rwnd)." },
  { id: "cn84", diff: "medium", topic: "Congestion", q: "UDP does not perform congestion control. What problem can this cause?", opts: ["Slower transmission speeds for UDP applications", "UDP traffic can congest shared links, starving TCP flows that do back off", "IPv4 addresses get exhausted more quickly", "Routing loops occur between UDP-heavy routers"], ans: 1, exp: "TCP backs off when it detects congestion. UDP doesn't. Heavy UDP traffic can fill buffers, causing TCP flows to throttle while UDP streams continue unabated â€” unfair bandwidth sharing." },
  { id: "cn85", diff: "medium", topic: "Security", q: "What type of attack floods a server with SYN requests without completing the handshake?", opts: ["Smurf Attack (ICMP amplification)", "SYN Flood DoS attack", "Man-in-the-Middle attack", "Session Replay attack"], ans: 1, exp: "A SYN Flood sends thousands of SYN packets (often spoofed IPs) but never sends the final ACK. The server allocates resources for each half-open connection until the table is exhausted." },
  { id: "cn86", diff: "medium", topic: "Security", q: "What is ARP poisoning / ARP spoofing?", opts: ["Sending malformed ARP packets to crash a switch", "Sending gratuitous ARP replies to associate the attacker's MAC with a legitimate IP, enabling a Man-in-the-Middle attack", "Flooding the network with excessive ARP broadcast requests", "Blocking all ARP responses on a subnet"], ans: 1, exp: "ARP spoofing sends unsolicited ARP replies, poisoning the victim's ARP cache. Traffic intended for the gateway flows through the attacker instead â€” enabling MITM, sniffing, or modification." },
  { id: "cn87", diff: "medium", topic: "Security", q: "Which type of firewall maintains state information about active connections?", opts: ["Simple packet filter (stateless)", "Stateless firewall â€” inspects each packet independently", "Stateful inspection firewall â€” tracks connection state", "Application gateway â€” operates at Layer 7 only"], ans: 2, exp: "A stateful firewall tracks connection state (SYN sent, established, FIN). It only allows return traffic for established sessions." },
  { id: "cn88", diff: "medium", topic: "Security", q: "What is the purpose of DNSSEC?", opts: ["Encrypt DNS query content to prevent eavesdropping", "Add digital signatures to DNS records, allowing resolvers to verify authenticity and prevent cache poisoning", "Speed up DNS resolution by caching more aggressively", "Assign DNS records to IP addresses dynamically"], ans: 1, exp: "DNSSEC uses public-key cryptography to sign DNS records (RRSIG). Resolvers validate signatures from the chain of trust rooted at the root zone, preventing Kaminsky-style cache poisoning." },
  { id: "cn89", diff: "medium", topic: "Security", q: "What is a DMZ in network security architecture?", opts: ["A private subnet reserved exclusively for internal database servers", "A perimeter network segment hosting public-facing services, isolated from the internal network by firewalls", "A type of encrypted VPN tunnel for remote workers", "A firewall bypass mechanism for trusted external partners"], ans: 1, exp: "A DMZ sits between two firewalls: one faces the internet, one faces the internal network. Web, mail, and DNS servers go here. If compromised, the internal network is still protected." },
  { id: "cn90", diff: "medium", topic: "Security", q: "What is Perfect Forward Secrecy (PFS) in TLS?", opts: ["Encryption that persists after the TLS session has ended", "Ephemeral key exchange (ECDHE/DHE) ensuring past sessions cannot be decrypted even if the server's long-term private key is later compromised", "A mechanism that prevents session replay attacks", "A certificate pinning technique to prevent rogue CA attacks"], ans: 1, exp: "Without PFS, an attacker recording TLS traffic can later decrypt it if they steal the server's private key. PFS uses ephemeral key exchange â€” session keys are generated fresh each time and discarded." },
  { id: "cn91", diff: "medium", topic: "Security", q: "What is a replay attack?", opts: ["Intercepting and modifying data packets in transit", "Capturing a valid authentication sequence and retransmitting it later to gain unauthorized access", "Flooding a network with traffic to exhaust resources", "Exploiting SQL injection vulnerabilities in a web application"], ans: 1, exp: "In a replay attack, valid captured data (login tokens, session cookies) is retransmitted. Defenses: timestamps/nonces, sequence numbers (IPSec), and short token expiry." },
  { id: "cn92", diff: "medium", topic: "Security", q: "What is port scanning and how do attackers use it?", opts: ["Measuring available bandwidth on specific network ports", "Probing TCP/UDP ports to discover running services and potential vulnerabilities for reconnaissance", "Encrypting data on specific protocol ports", "Assigning dynamic port numbers to running applications"], ans: 1, exp: "Port scanning (Nmap is the classic tool) probes ports to identify open services. Attackers use this to build a map of attack surface before exploitation." },
  { id: "cn93", diff: "medium", topic: "Security", q: "What is the difference between symmetric and asymmetric encryption?", opts: ["Symmetric is slower; asymmetric is always faster", "Symmetric uses one shared key (fast, e.g., AES); asymmetric uses a public/private key pair (slower, solves key distribution, e.g., RSA)", "Symmetric is used for authentication; asymmetric is for bulk data encryption", "Both are identical in performance and security properties"], ans: 1, exp: "Symmetric (AES, ChaCha20): fast, ideal for bulk data, but key must be securely shared. Asymmetric (RSA, ECDH): solves key distribution but is computationally expensive. TLS uses asymmetric for handshake, symmetric for data." },
  { id: "cn94", diff: "medium", topic: "Security", q: "What is the role of a Certificate Authority (CA) in TLS/PKI?", opts: ["Encrypts web traffic directly between client and server", "Issues and digitally signs certificates, binding a public key to an identity â€” browsers trust CAs to validate server authenticity", "Assigns IP addresses to web servers for certificate issuance", "Generates the symmetric session keys used to encrypt TLS traffic"], ans: 1, exp: "A CA vouches for identity. The server's certificate (signed by the CA) contains its public key. The client verifies the CA's signature using its root certificate (pre-installed in browsers/OS). This is the chain of trust." },
  { id: "cn95", diff: "medium", topic: "Security", q: "What is a VPN and how does it provide security?", opts: ["A virtual physical network built with dedicated leased lines", "An encrypted tunnel over the public internet â€” data is encrypted at source, tunneled, and decrypted at destination", "A protocol that makes network routing faster", "A special type of VLAN for remote users"], ans: 1, exp: "A VPN encapsulates and encrypts traffic between endpoints over the public internet. IPSec VPN encrypts at Layer 3. SSL/TLS VPN uses HTTPS. WireGuard is a modern, fast alternative." },
  { id: "cn96", diff: "medium", topic: "Security", q: "What is OAuth 2.0's role in API security?", opts: ["OAuth 2.0 is a network routing and authentication protocol", "OAuth 2.0 is an authorization framework â€” issues scoped access tokens to third-party apps without exposing user credentials", "OAuth 2.0 encrypts all API traffic between client and server", "OAuth 2.0 is a direct replacement for TLS in API communications"], ans: 1, exp: "OAuth 2.0 delegates access: instead of sharing passwords, users grant third-party apps access tokens with specific scopes. Not an authentication protocol â€” that's OpenID Connect." },
  { id: "cn97", diff: "medium", topic: "TCP/IP", q: "What is the purpose of the TCP sliding window?", opts: ["Encrypt data segments during transmission", "Allow multiple segments to be sent before waiting for ACK, based on receiver's advertised buffer size", "Fragment large segments into smaller IP packets", "Handle DNS resolution within the TCP stack"], ans: 1, exp: "Without sliding window, TCP would wait for an ACK per segment (stop-and-wait) â€” very slow over high-latency links. Sliding window allows 'window size' bytes to be in flight simultaneously." },
  { id: "cn98", diff: "medium", topic: "TCP/IP", q: "What is the purpose of TCP's TIME_WAIT state?", opts: ["Wait for the remote server to close the connection first", "Ensure any delayed duplicate segments from the old connection expire before a new connection with same IP/port reuses them", "Buffer additional incoming data after connection close", "Trigger retransmission of the final FIN packet"], ans: 1, exp: "TIME_WAIT lasts 2Ã—MSL (Maximum Segment Lifetime, typically 60s). It ensures the final ACK is delivered, and delayed segments from the old connection expire before a new connection begins." },
  { id: "cn99", diff: "medium", topic: "TCP/IP", q: "What is the Nagle algorithm in TCP?", opts: ["A congestion control mechanism for high-bandwidth links", "Combines small outgoing TCP segments into larger ones to reduce packet overhead â€” can add latency in interactive applications", "A retransmission algorithm for recovering from burst packet loss", "A flow control mechanism that adjusts the receiver window size"], ans: 1, exp: "Nagle buffers small writes until a full MSS or an ACK arrives. Great for bulk transfers, but harmful for interactive protocols (SSH keystrokes, online gaming). Disabled with TCP_NODELAY." },
  { id: "cn100", diff: "medium", topic: "TCP/IP", q: "How does SACK (Selective Acknowledgment) improve TCP efficiency?", opts: ["TCP doesn't handle out-of-order packet delivery at all", "Without SACK, TCP retransmits from the first gap onward. SACK allows the receiver to report non-contiguous received ranges, so only truly missing segments are retransmitted", "SACK reduces the TCP window size to prevent congestion", "SACK is a mechanism used only in UDP-based reliable protocols"], ans: 1, exp: "Classic TCP (without SACK): if segment 5 of 10 is lost, retransmit from 5 even if 6-10 arrived. With SACK: receiver says 'I have 1-4 and 6-10, only missing 5.' Sender retransmits only segment 5." },
  { id: "cn101", diff: "medium", topic: "TCP/IP", q: "TCP zero window: the receiver sets window size to 0. What happens?", opts: ["The TCP connection is immediately terminated by both sides", "The sender stops transmitting and periodically sends TCP Zero Window Probe segments to check if the window has reopened", "The sender continues transmitting, buffering data at the router", "The router buffers all data until the receiver window reopens"], ans: 1, exp: "Zero window = receiver buffer is full (back-pressure). The sender pauses but sends Zero Window Probes to check for window updates. When the application drains the buffer, the receiver sends a Window Update." },
  { id: "cn102", diff: "medium", topic: "TCP/IP", q: "What is TCP head-of-line blocking and why did HTTP/2 not fully solve it?", opts: ["HOL blocking is a Layer 2 issue unrelated to TCP behavior", "A lost TCP segment blocks all subsequent data in the byte stream. HTTP/2 multiplexes streams over one TCP connection â€” all streams stall on any single TCP loss. HTTP/3/QUIC solves this", "HTTP/2 completely eliminated HOL blocking through stream multiplexing", "HOL blocking only affects UDP-based transport protocols"], ans: 1, exp: "TCP delivers a byte stream in order. One lost segment stalls everything behind it. HTTP/2's multiplexing over one TCP connection means all streams are blocked by a single TCP loss. HTTP/3 over QUIC runs each stream independently." },
  { id: "cn103", diff: "medium", topic: "TCP/IP", q: "IPv6 uses which mechanism instead of broadcast?", opts: ["Anycast â€” one-to-nearest delivery", "Multicast â€” one-to-many delivery to subscribed groups", "Regular unicast with a higher TTL", "Broadcast with TTL limited to 1 hop"], ans: 1, exp: "IPv6 eliminates broadcast. Neighbor Discovery (NDP, which replaces ARP) uses link-local multicast. All-routers multicast (FF02::2), Solicited-Node multicast addresses reduce unnecessary traffic." },
  { id: "cn104", diff: "medium", topic: "Data Link", q: "What is the purpose of the CRC field in an Ethernet frame?", opts: ["Identify the original sender's hardware address", "Encrypt the payload for transmission security", "Detect bit errors introduced during transmission", "Fragment frames that exceed the MTU"], ans: 2, exp: "CRC (Cyclic Redundancy Check) is a checksum appended to the frame. The receiver recalculates CRC; if it doesn't match, the frame is silently discarded." },
  { id: "cn105", diff: "medium", topic: "Data Link", q: "What is the purpose of the 802.1Q tag in Ethernet frames?", opts: ["Fragment Ethernet frames larger than the MTU", "Insert a 4-byte VLAN identifier tag to carry multiple VLANs across trunk links", "Encrypt the frame payload for inter-VLAN security", "Add precise timestamps for latency measurement"], ans: 1, exp: "802.1Q inserts a 4-byte tag between the source MAC and EtherType: 2-byte TPID (0x8100) + 2-byte TCI (3-bit priority + 1-bit DEI + 12-bit VLAN ID). This allows 4094 VLANs on a single trunk." },
  { id: "cn106", diff: "medium", topic: "Data Link", q: "What is CSMA/CA and where is it used?", opts: ["Used in Ethernet to detect collisions after they occur", "Used in 802.11 Wi-Fi to avoid collisions â€” wireless nodes can't detect collisions while transmitting, so they avoid them proactively", "Used exclusively in fiber optic networks", "Used only in legacy half-duplex Ethernet segments"], ans: 1, exp: "Wi-Fi can't detect collisions (half-duplex wireless). CSMA/CA uses: listen before transmit, RTS/CTS optional handshake, random backoff timers. ACKs confirm delivery." },
  { id: "cn107", diff: "medium", topic: "Data Link", q: "What is the maximum payload (MTU) of a standard Ethernet frame?", opts: ["512 bytes", "1024 bytes", "1500 bytes", "9000 bytes (Jumbo frames only)"], ans: 2, exp: "Standard Ethernet MTU = 1500 bytes. Jumbo frames (up to 9000 bytes) require explicit support on all devices and can improve throughput for storage traffic." },
  { id: "cn108", diff: "medium", topic: "Data Link", q: "What is the difference between half-duplex and full-duplex communication?", opts: ["Half-duplex is encrypted; full-duplex is unencrypted", "Half-duplex allows simultaneous bidirectional; full-duplex is one direction at a time", "Full-duplex allows simultaneous send and receive; half-duplex is one direction at a time (walkie-talkie model)", "Half-duplex uses fiber optic; full-duplex uses copper cables"], ans: 2, exp: "Full-duplex (modern switched Ethernet): send and receive simultaneously, no collisions, CSMA/CD disabled. Half-duplex (hubs, old coax Ethernet): only one at a time â€” CSMA/CD active." },
  { id: "cn109", diff: "medium", topic: "App Layer", q: "A user accesses www.example.com. What is the correct order of protocol involvement?", opts: ["HTTP â†’ DNS â†’ TCP â†’ IP", "DNS resolution â†’ TCP handshake â†’ IP routing â†’ HTTP request", "DNS â†’ IP routing â†’ TCP â†’ HTTP", "TCP handshake â†’ DNS â†’ HTTP â†’ IP"], ans: 1, exp: "Step-by-step: 1) DNS resolves domain â†’ IP, 2) TCP three-way handshake, 3) IP routes each packet, 4) HTTP GET request is sent and response received." },
  { id: "cn110", diff: "medium", topic: "App Layer", q: "What is the key difference between HTTP/1.1 and HTTP/2?", opts: ["HTTP/2 uses UDP instead of TCP", "HTTP/2 supports multiplexing â€” multiple requests over a single connection simultaneously, with header compression and binary framing", "HTTP/1.1 supports compression; HTTP/2 dropped it", "HTTP/2 is unencrypted; HTTP/1.1 supports TLS"], ans: 1, exp: "HTTP/1.1 suffers from HOL blocking (one request at a time per connection). HTTP/2 introduces multiplexing (multiple streams), HPACK header compression, and binary framing." },
  { id: "cn111", diff: "medium", topic: "App Layer", q: "What is the function of a CDN (Content Delivery Network)?", opts: ["A protocol for encrypting content at the application layer", "Caches and serves content from edge servers geographically close to users â€” reducing latency and origin server load", "Acts as a web application firewall between clients and servers", "A DNS-based load balancer that only routes requests, not content"], ans: 1, exp: "CDNs (Cloudflare, Akamai, AWS CloudFront) cache static assets on PoPs worldwide. Users connect to the nearest PoP â€” reducing RTT, offloading origin, and improving availability." },
  { id: "cn112", diff: "medium", topic: "App Layer", q: "HTTP is stateless. How do web applications maintain state across requests?", opts: ["HTTP/2 added native stateful session support", "Cookies, session tokens, and JWT are application-layer mechanisms that simulate statefulness over stateless HTTP", "HTTP is not actually stateless â€” TCP connection persistence provides state", "Only TCP keep-alive makes HTTP stateful across requests"], ans: 1, exp: "HTTP has no built-in memory between requests. Cookies persist tokens on the client. Server-side sessions link session IDs to server-stored state. JWTs carry signed claims in the token itself." },
  { id: "cn113", diff: "medium", topic: "App Layer", q: "A company's email server uses port 587 instead of 25. What is the likely reason?", opts: ["Port 25 is reserved exclusively for POP3 email retrieval", "Port 587 (SMTP submission with STARTTLS) is for authenticated client submission; ISPs block port 25 to prevent spam", "Port 587 is inherently faster than port 25 for SMTP", "Port 587 uses UDP while port 25 uses TCP"], ans: 1, exp: "Port 25: server-to-server SMTP relay (often blocked by ISPs to prevent spam). Port 587: SMTP submission â€” clients authenticate before sending, with STARTTLS for encryption." },
  { id: "cn114", diff: "hard", topic: "Routing", q: "BGP best-path: Peer A has AS_PATH length 3; Peer B has longer AS_PATH but higher LOCAL_PREF. Which is preferred?", opts: ["Peer A â€” shorter AS_PATH always takes precedence", "Peer B â€” LOCAL_PREF is evaluated before AS_PATH length in BGP best-path selection", "Peer A â€” eBGP routes are always preferred over all other attributes", "Both routes are installed in the table with equal cost"], ans: 1, exp: "BGP best-path order: Weight â†’ LOCAL_PREF â†’ Locally originated â†’ AS_PATH length â†’ Origin â†’ MED â†’ eBGP > iBGP â†’ IGP metric â†’ Router ID. LOCAL_PREF (step 2) is evaluated before AS_PATH (step 4)." },
  { id: "cn115", diff: "hard", topic: "Routing", q: "What is the difference between iBGP and eBGP, and why does iBGP require a full mesh or route reflectors?", opts: ["iBGP is within an AS; eBGP is between ASes. iBGP requires full mesh because it does not re-advertise routes learned from one iBGP peer to another", "iBGP is faster than eBGP due to shorter paths within an AS", "eBGP requires a full mesh; iBGP does not have this requirement", "They are identical protocols except for their administrative distance values"], ans: 0, exp: "iBGP split horizon: routes learned from iBGP peers are NOT re-advertised to other iBGP peers (loop prevention). This creates an iBGP full-mesh requirement (n(n-1)/2 sessions). Route Reflectors or BGP Confederations scale iBGP without full mesh." },
  { id: "cn116", diff: "hard", topic: "Routing", q: "What is OSPF Area 0 and what happens if an area can't connect to it directly?", opts: ["Area 0 is for external routes; internal areas don't need to connect to it", "Area 0 is the backbone; all areas must connect to it. Discontiguous areas use OSPF virtual links through a transit area", "Area 0 is an optional performance optimization", "Each area in OSPF uses its own independent algorithm and doesn't need Area 0"], ans: 1, exp: "All OSPF areas must connect to Area 0 (backbone) to receive inter-area routes from ABRs. If a non-backbone area is disconnected, a virtual link is configured through a transit area." },
  { id: "cn117", diff: "hard", topic: "Routing", q: "In OSPF, what is the difference between E1 and E2 external LSAs (Type 5)?", opts: ["E1 is for inter-area routes; E2 is for intra-area routes", "E1 adds the internal OSPF path cost to the external cost (cumulative); E2 uses only the external cost (constant) â€” E1 gives more accurate end-to-end cost comparison", "E2 is always preferred over E1 by the OSPF algorithm", "E1 uses hop count; E2 uses bandwidth as the metric"], ans: 1, exp: "E2 (default): the metric never changes as the route is advertised inside OSPF â€” only the external cost matters. E1: internal OSPF cost is added to the external cost, reflecting true end-to-end cost." },
  { id: "cn118", diff: "hard", topic: "Routing", q: "What is ECMP (Equal-Cost Multi-Path routing) and what limitation affects stateful flows?", opts: ["ECMP is a routing protocol for multicast traffic distribution", "ECMP installs multiple equal-cost routes, distributing traffic across paths; limitation: asymmetric routing can break stateful firewalls that track sessions directionally", "ECMP is a load-balancing protocol that only works with BGP", "ECMP guarantees packet ordering across all distributed paths"], ans: 1, exp: "ECMP installs multiple next-hops for the same destination. Per-flow hashing keeps packets of the same flow on the same path. Asymmetric routing (different paths in/out) can break stateful firewalls/NAT." },
  { id: "cn119", diff: "hard", topic: "Routing", q: "What is MPLS and how does label switching differ from traditional IP routing?", opts: ["MPLS is a network security protocol for encrypting routing tables", "MPLS adds a label stack between L2 and L3; LSRs forward based on exact-match label lookups â€” faster than IP LPM, enabling VPNs, TE, and QoS at scale", "MPLS permanently replaces IP addresses with labels end-to-end", "MPLS requires physically separate hardware infrastructure from IP networks"], ans: 1, exp: "MPLS labels (20-bit) are pushed at the ingress LER and popped at the egress LER. Transit LSRs swap labels using a simple exact-match table â€” much faster than IP LPM. Enables L3VPNs, Traffic Engineering (RSVP-TE), and QoS." },
  { id: "cn120", diff: "hard", topic: "Routing", q: "What is Segment Routing (SR) and how does it simplify MPLS Traffic Engineering?", opts: ["Segment Routing is a replacement for BGP in large-scale networks", "SR encodes the explicit path as a stack of Segment IDs in the packet header â€” transit routers need no per-LSP state (unlike RSVP-TE), with only the ingress node knowing the path", "SR requires a full mesh of tunnels between all routers", "SR uses hop count for path selection and cannot support bandwidth constraints"], ans: 1, exp: "RSVP-TE requires per-LSP signaling state at every router. SR-MPLS or SRv6 embeds the entire path as an ordered list of SIDs in the packet. Transit nodes just follow instructions â€” no per-path state, simplifying TE." },
  { id: "cn121", diff: "hard", topic: "Routing", q: "What is BGP NEXT_HOP processing and why is 'next-hop-self' important in iBGP?", opts: ["NEXT_HOP is always set to the originating router's address in all BGP sessions", "iBGP preserves the eBGP peer's IP as NEXT_HOP â€” which internal routers may lack a route to. 'next-hop-self' replaces it with the iBGP router's own address, ensuring reachability", "NEXT_HOP is only relevant in IPv6 BGP sessions", "'next-hop-self' is only required when using BGP route reflectors"], ans: 1, exp: "When an eBGP-learned route is re-advertised via iBGP, the NEXT_HOP attribute retains the external eBGP peer's IP. Internal routers may not have a route to that external IP. Configuring 'next-hop-self' changes NEXT_HOP to the advertising router's interface address." },
  { id: "cn122", diff: "hard", topic: "Routing", q: "What is a BGP confederation and when is it preferred over route reflectors?", opts: ["A BGP confederation is merely a marketing term for iBGP optimization", "Confederations divide an AS into sub-ASes with eBGP-like sessions between them, preserving full BGP attributes (MED, LOCAL_PREF) across the AS â€” preferred when full attribute transparency and complex policy are needed", "Confederations are always simpler to implement than route reflectors", "Confederations entirely replace iBGP, eliminating the need for peer relationships"], ans: 1, exp: "Route reflectors may distort MED comparisons across clusters. BGP confederations create sub-ASes with genuine eBGP between them â€” attributes like MED are properly compared. Trade-off: more complex configuration but more precise policy control." },
  { id: "cn123", diff: "hard", topic: "Routing", q: "What is the count-to-infinity problem in RIP and what is its maximum impact?", opts: ["Routers loop packets indefinitely with unbounded metric growth", "After a link failure, routers iteratively increase metrics from stale information; in RIP the max is 15 update cycles (Ã—30s each) before declaring the route unreachable", "Routes are immediately deleted from all routers when a failure is detected", "Count-to-infinity only affects OSPF networks, not distance-vector protocols"], ans: 1, exp: "Example: R1-R2-R3, R3's link fails. R2 thinks R1 can still reach R3 (old advertisement). They increment the metric back and forth: 2â†’3â†’4â†’...â†’16. At 16 (infinity in RIP), the route is finally removed. This can take 7.5+ minutes with 30s timers." },
  { id: "cn124", diff: "hard", topic: "Routing", q: "What is RTBH (Remotely Triggered Black Hole) routing and how does it mitigate DDoS?", opts: ["RTBH is a misconfigured static route that causes packet loss", "RTBH uses BGP to signal upstream ISPs to discard traffic destined to a victim /32 at the network edge, stopping DDoS traffic before it enters your network", "RTBH is a hidden BGP route never advertised to any peers", "RTBH is a routing technique that bypasses firewall inspection rules"], ans: 1, exp: "During a DDoS, announce victim_IP/32 with a BGP community that triggers upstream ISPs to route it to Null0. DDoS traffic is absorbed at the ISP edge. Trade-off: the attacked IP becomes unreachable." },
  { id: "cn125", diff: "hard", topic: "Congestion", q: "TCP CUBIC vs. TCP Reno: why does CUBIC outperform Reno on high-BDP networks?", opts: ["CUBIC uses faster packet retransmission than Reno", "CUBIC uses a cubic function for cwnd growth based on time since last loss â€” recovering faster and growing more aggressively; Reno's linear growth is too conservative for high-bandwidth, high-latency paths", "CUBIC completely disables the Slow Start phase", "CUBIC uses UDP internally to bypass TCP congestion signals"], ans: 1, exp: "Reno's Congestion Avoidance: +1 MSS per RTT â€” too slow to fill a 10Gbps Ã— 100ms pipe. CUBIC: w(t) = C(t-K)Â³ + w_max â€” grows aggressively when far from the last loss point, converges smoothly near it." },
  { id: "cn126", diff: "hard", topic: "Congestion", q: "What is BBR (Bottleneck Bandwidth and RTT) and how does it fundamentally differ from loss-based algorithms?", opts: ["BBR is loss-based like Reno, just with a different backoff strategy", "BBR models the network path (bottleneck BW Ã— min RTT) to set the send rate directly â€” it doesn't use packet loss as the primary signal, avoiding buffer inflation and achieving better throughput on high-latency or lossy paths", "BBR is designed exclusively for UDP-based protocols", "BBR is functionally equivalent to CUBIC with just different naming"], ans: 1, exp: "Loss-based algorithms fill buffers until packets drop â€” causing high queuing latency. BBR continuously measures bottleneck bandwidth (max delivery rate) and min RTT (min latency), sending at the optimal rate without filling buffers." },
  { id: "cn127", diff: "hard", topic: "Congestion", q: "What is Bufferbloat and how does it affect interactive applications?", opts: ["Bufferbloat refers to having too many network buffers configured in router hardware", "Excessively large router/modem buffers cause seconds of queuing latency during congestion â€” bulk transfers maintain throughput but interactive apps (VoIP, gaming) experience intolerable lag", "Bufferbloat is a type of buffer overflow security attack", "Bufferbloat is a memory leak that occurs in routing table management"], ans: 1, exp: "Large buffers are filled during bulk transfers, creating a queue. Packets spend 500ms+ in the queue, killing interactive latency. CoDel (Controlled Delay) and FQ-CoDel keep queues short while maintaining throughput." },
  { id: "cn128", diff: "hard", topic: "Congestion", q: "What is the difference between TCP Tahoe and TCP Reno after detecting packet loss?", opts: ["TCP Tahoe and Reno handle all types of loss identically", "Tahoe always resets cwnd to 1 MSS on any loss detection. Reno differentiates: triple duplicate ACKs trigger Fast Recovery (cwnd=ssthresh, not 1), avoiding expensive full Slow Start", "Reno is the older algorithm; Tahoe was developed as its replacement", "Tahoe supports ECN natively; Reno does not include ECN support"], ans: 1, exp: "TCP Tahoe: any loss (timeout OR triple dup ACK) â†’ ssthresh=cwnd/2, cwnd=1, restart Slow Start. TCP Reno: timeout â†’ same as Tahoe. Triple dup ACK â†’ Fast Retransmit + Fast Recovery: ssthresh=cwnd/2, cwnd=ssthresh." },
  { id: "cn129", diff: "hard", topic: "Congestion", q: "What is the Bandwidth-Delay Product (BDP) and its implication for TCP buffer tuning?", opts: ["BDP measures the total router CPU capacity required for network traffic", "BDP = bandwidth Ã— RTT = the amount of data that must be 'in flight' to fully utilize a link. Default OS TCP buffers are often too small for high-BDP paths, capping throughput", "BDP is relevant only for UDP-based applications and media streaming", "Larger BDP automatically improves TCP throughput without any configuration changes"], ans: 1, exp: "Example: 1Gbps Ã— 100ms RTT = 12.5MB BDP. If TCP socket buffer is capped at 256KB, max throughput = 256KB / 0.1s = 20Mbps â€” only 2% of link capacity! Tune with tcp_rmem/tcp_wmem on Linux." },
  { id: "cn130", diff: "hard", topic: "Congestion", q: "QUIC runs over UDP but implements reliability. What specific advantage does this give HTTP/3?", opts: ["Lower encryption overhead compared to TLS 1.3 over TCP", "Eliminates transport-layer head-of-line blocking â€” a lost UDP datagram only blocks its own QUIC stream, not all other concurrent streams", "Skips the connection establishment phase entirely for all connections", "QUIC removes the need for any congestion control mechanism"], ans: 1, exp: "HTTP/2 over TCP: all multiplexed streams share one TCP byte stream. One lost TCP segment blocks ALL streams. HTTP/3 over QUIC: each stream is independently reliable. A lost packet only affects its own stream. Plus 0-RTT and built-in TLS 1.3." },
  { id: "cn131", diff: "hard", topic: "Security", q: "Why doesn't HTTPS prevent all Man-in-the-Middle attacks? What additional mechanisms are needed?", opts: ["HTTPS with a valid certificate prevents all possible MITM attacks completely", "HTTPS can be bypassed via SSL stripping (downgrade to HTTP) or rogue/compromised CAs. HSTS (preloading) and Certificate Transparency logs provide additional protection", "HTTPS is only vulnerable to MITM on HTTP/1.1 connections", "HTTPS only protects data at rest on the server, not data in transit"], ans: 1, exp: "SSL Stripping: attacker intercepts first HTTP request before HTTPS redirect. Fix: HSTS with preloading (browser always goes directly to HTTPS). Rogue CAs can issue fraudulent certs â€” CT logs make this detectable." },
  { id: "cn132", diff: "hard", topic: "Security", q: "What is BGP hijacking and how does RPKI mitigate it?", opts: ["BGP hijacking is a physical attack on internet cables; RPKI encrypts fiber connections", "A malicious AS advertises IP prefixes it doesn't own to attract traffic through it; RPKI cryptographically binds prefixes to authorized origin ASes using signed ROA objects", "BGP hijacking is a DNS-based attack; RPKI provides DNS-level protection", "BGP hijacking only affects local area networks; ISPs are automatically protected"], ans: 1, exp: "Examples: Pakistan Telecom hijacking YouTube (2008), Rostelecom hijacking financial routes (2020). RPKI: prefix owners create Route Origin Authorizations (ROAs) signed with their IANA-allocated key. Routers validate: if no ROA or wrong ASN â†’ Invalid â†’ drop." },
  { id: "cn133", diff: "hard", topic: "Security", q: "What is a timing side-channel attack? Provide a concrete network security example.", opts: ["A DoS attack that exploits precise timestamps in network packet headers", "An attack that exploits measurable differences in execution time to infer secret information â€” e.g., TLS CBC-mode padding oracle attacks measuring server response time differences", "A replay attack that uses expired authentication timestamps", "A Man-in-the-Middle attack that exploits NTP time synchronization"], ans: 1, exp: "Lucky 13: TLS CBC-mode HMAC verification took slightly different time based on padding length. An active attacker could send crafted ciphertexts and measure response times (nanosecond differences) to statistically determine plaintext content." },
  { id: "cn134", diff: "hard", topic: "Security", q: "What is HSTS (HTTP Strict Transport Security) and what specific attack does it prevent?", opts: ["HSTS is a response header that speeds up HTTPS connections through caching", "HSTS instructs browsers to always connect via HTTPS for a domain (with max-age), preventing SSL stripping attacks that downgrade the initial connection to HTTP", "HSTS is a certificate validation mechanism that pins specific CA certificates", "HSTS is a rate-limiting header that prevents DDoS attacks against HTTPS servers"], ans: 1, exp: "Without HSTS: attacker intercepts first HTTP request (before redirect to HTTPS) and maintains HTTP with victim. With HSTS: browser remembers it must use HTTPS directly â€” even the first request is HTTPS, eliminating the downgrade window." },
  { id: "cn135", diff: "hard", topic: "Security", q: "What is a VLAN hopping attack and how is it prevented?", opts: ["Accessing other VLANs by sending traffic through a NAT device", "Double-tagging attack: crafting frames with two 802.1Q tags where the outer tag matches the native VLAN; or Switch Spoofing: exploiting DTP to form an unauthorized trunk â€” both allow access to other VLANs", "VLAN hopping is a physical cable reconnection attack", "VLAN hopping is an ARP-based attack that works only on IPv6 networks"], ans: 1, exp: "Double-tag: send frame with outer VLAN=native (stripped by first switch) and inner VLAN=target. Switch spoofing: force DTP negotiation. Prevention: disable DTP ('switchport nonegotiate'), set native VLAN to an unused ID, enable BPDU Guard." },
  { id: "cn136", diff: "hard", topic: "Security", q: "What is a supply chain attack and how did SolarWinds demonstrate this vector?", opts: ["An attack targeting physical network supply warehouses and shipping infrastructure", "Attackers compromise a trusted software vendor's build pipeline to distribute trojaned updates â€” SolarWinds: SUNBURST backdoor was inserted into digitally-signed Orion updates, silently infecting 18,000+ organizations", "An attack conducted exclusively through ISP infrastructure and upstream providers", "A hardware trojan physically inserted into network cables during manufacturing"], ans: 1, exp: "SolarWinds 2020: attackers (APT29/Cozy Bear) compromised SolarWinds' build server, injecting SUNBURST backdoor into Orion software updates. The updates were digitally signed â€” customers trusted them. Defense: SBOM, reproducible builds, code signing with hardware keys." },
  { id: "cn137", diff: "hard", topic: "Security", q: "What is AES-ECB mode vulnerable to in a chosen-plaintext attack (CPA)?", opts: ["ECB is vulnerable to brute-force attacks on the AES key length", "ECB encrypts each block independently â€” identical plaintext blocks produce identical ciphertext blocks, leaking data patterns. Secure modes (CBC, CTR, GCM) use IVs/nonces to prevent this", "ECB mode is only vulnerable to attacks with physical access to hardware", "CPA only affects asymmetric encryption algorithms, not symmetric block ciphers"], ans: 1, exp: "AES-ECB: each 16-byte block is encrypted identically. The classic example: encrypting a bitmap image with ECB mode â€” the image structure remains clearly visible in the ciphertext. Modes with IVs/nonces ensure identical plaintexts produce different ciphertexts." },
  { id: "cn138", diff: "hard", topic: "Security", q: "What is Perfect Forward Secrecy (PFS) and why is it critical in TLS?", opts: ["PFS is encryption that continues to protect data even after a session has ended (at-rest encryption)", "PFS uses ephemeral key exchange (ECDHE/DHE) so that compromise of the server's long-term private key cannot decrypt previously recorded sessions â€” each session generates unique throwaway keys", "PFS is a mechanism specifically designed to prevent replay attacks in TLS sessions", "PFS is a certificate pinning technique to prevent rogue Certificate Authority attacks"], ans: 1, exp: "Without PFS: attacker records encrypted TLS sessions, later obtains server private key â†’ decrypts all historical sessions. With PFS (ECDHE): session key = ephemeral keypair Ã— ephemeral keypair â€” discarded after use. Required for compliance (PCI-DSS, HIPAA)." },
  { id: "cn139", diff: "hard", topic: "Security", q: "What is the difference between an IDS and an IPS in terms of deployment and capability?", opts: ["IDS blocks malicious traffic in real time; IPS only monitors and sends alerts", "IDS passively monitors a copy of traffic (out-of-band) and alerts; IPS is deployed inline and actively blocks malicious traffic in real time â€” but adds latency and false positives can block legitimate traffic", "They are functionally identical products with different branding", "IDS is designed for wired networks; IPS is designed specifically for wireless environments"], ans: 1, exp: "IDS (out-of-band/span port): sees a copy of traffic, generates alerts, zero performance impact, cannot block. IPS (inline): can drop/reset malicious flows in real time but adds latency; false positives can cause legitimate traffic outages. NGFW often integrates IPS functionality." },
  { id: "cn140", diff: "hard", topic: "Security", q: "What is a zero-day vulnerability and why is it uniquely dangerous?", opts: ["A software vulnerability that was discovered within 24 hours of the software being released", "A publicly undisclosed vulnerability with no available vendor patch â€” attackers can exploit it freely while defenders have zero protection until a patch or mitigation is available", "A software bug that only affects brand-new versions of software releases", "A denial-of-service attack that targets application startup and zero-state initialization"], ans: 1, exp: "Zero-days are valuable on the black market (millions for iOS/browser zero-days). Stuxnet used 4 zero-days simultaneously. Defenders rely on behavioral detection, network segmentation, and least-privilege to limit zero-day blast radius." },
  { id: "cn141", diff: "hard", topic: "Security", q: "What is micro-segmentation in Zero Trust network architecture?", opts: ["Dividing an IP block into many small /30 subnets for address efficiency", "Applying fine-grained, identity-aware security policies at the individual workload/VM level for east-west (lateral) traffic â€” not just at the perimeter", "A VLAN-based traffic segmentation technique used for broadcast domain reduction", "Physically separating servers onto different network cards in a data center"], ans: 1, exp: "Traditional firewalls protect north-south (in/out) traffic but allow lateral movement once inside. Micro-segmentation (VMware NSX, Cisco ACI, Illumio) enforces policies between individual workloads." },
  { id: "cn142", diff: "hard", topic: "Security", q: "What is DNS cache poisoning (Kaminsky attack) and how does DNSSEC prevent it?", opts: ["Overloading a DNS server with queries to exhaust its cache capacity", "Injecting forged DNS responses into a resolver's cache by winning a race condition â€” pointing domains to attacker IPs. DNSSEC prevents this with cryptographic signatures on every DNS record", "A brute-force attack that guesses DNS resolver administrator passwords", "DNS cache poisoning only affects authoritative DNS servers, not recursive resolvers"], ans: 1, exp: "Kaminsky (2008): attacker floods resolver with forged UDP responses for a subdomain, racing to poison the cache. DNSSEC: every record is signed (RRSIG), resolver verifies the signature chain up to the root. Forged responses lack valid signatures â†’ rejected." },
  { id: "cn143", diff: "hard", topic: "Security", q: "What is certificate transparency (CT) and what attack does it specifically mitigate?", opts: ["CT is a method to speed up certificate chain validation in browsers", "CT is a public, append-only, auditable log of all issued TLS certificates â€” it allows domain owners and researchers to detect unauthorized or misissued certificates from rogue CAs", "CT is a certificate compression algorithm that reduces TLS handshake size", "CT is a certificate revocation mechanism that replaces OCSP and CRL"], ans: 1, exp: "Without CT, a compromised CA could issue a certificate for google.com and use it for MITM â€” undetectable. CT logs record every issued certificate. Browsers require SCTs. Domain owners monitor logs and can quickly detect and revoke fraudulent certificates." },
  { id: "cn144", diff: "hard", topic: "Security", q: "What is OAuth 2.0 Authorization Code Flow and why is it more secure than the deprecated Implicit Flow?", opts: ["They are identical in security properties with different implementation names", "Authorization Code: the auth code is exchanged server-to-server for a token â€” access token never exposed in the browser. Implicit Flow: access token delivered in the URL fragment, visible to browser history, JS, and referrer headers â€” easily stolen", "Implicit Flow is actually more secure because it uses fewer network round trips", "Authorization Code Flow is only designed for mobile and native application clients"], ans: 1, exp: "Implicit Flow was designed for single-page apps before CORS. The access token appears in the URL fragment â€” exposed to browser history, JS, and referrer headers. Authorization Code + PKCE: only a short-lived code in the URL; token exchange happens server-side." },
  { id: "cn145", diff: "hard", topic: "Security", q: "What is an SSRF (Server-Side Request Forgery) attack and why is it critical in cloud environments?", opts: ["SSRF is a client-side injection attack targeting web browsers", "SSRF tricks a server into making HTTP requests to internal resources â€” in AWS, this can access the EC2 metadata service at 169.254.169.254, stealing IAM credentials with full cloud access", "SSRF is a DDoS attack that exhausts server connection pools", "SSRF is an SSL certificate forgery attack specific to cloud load balancers"], ans: 1, exp: "AWS IMDSv1 had no authentication â€” any SSRF could hit 169.254.169.254/latest/meta-data/iam/security-credentials/ and steal IAM role credentials. Capital One breach (2019) was a SSRF â†’ credential theft â†’ S3 data exfiltration. IMDSv2 requires session-oriented requests." },
  { id: "cn146", diff: "hard", topic: "Protocols", q: "What is QUIC 0-RTT connection establishment and what is the security trade-off?", opts: ["QUIC 0-RTT requires no encryption and bypasses TLS for connection setup speed", "QUIC uses cached TLS session parameters (PSK) from prior connections to send application data in the very first packet â€” 0-RTT data is vulnerable to replay attacks if the server accepts it non-idempotently", "QUIC 0-RTT is identical to TCP Fast Open in all security properties", "QUIC 0-RTT eliminates all need for congestion control during session resumption"], ans: 1, exp: "0-RTT: client caches session ticket from previous connection; in the next connection, sends app data immediately without waiting for a handshake. Replay risk: an attacker could resend the 0-RTT data. Mitigation: 0-RTT data should only be used for idempotent requests." },
  { id: "cn147", diff: "hard", topic: "Protocols", q: "What is TLS 1.3 and how does its handshake differ from TLS 1.2 in terms of latency?", opts: ["TLS 1.3 requires more round trips than TLS 1.2 due to stronger cipher requirements", "TLS 1.3 achieves 1-RTT handshake (vs TLS 1.2's 2-RTT) by combining key exchange with ClientHello, and supports 0-RTT session resumption. It also removed all weak ciphers", "TLS 1.3 removed cipher suite negotiation, breaking all legacy TLS 1.2 deployments", "TLS 1.3 is significantly slower than TLS 1.2 due to its stronger mandatory encryption requirements"], ans: 1, exp: "TLS 1.2: ClientHello â†’ ServerHello (1 RTT) â†’ Certificate+Finished (2nd RTT) â†’ data. TLS 1.3: ClientHello includes key_share (ECDHE public key) â†’ server can immediately compute session keys â†’ data after 1 RTT. Also removed RSA key exchange, MD5/SHA-1, CBC cipher suites." },
  { id: "cn148", diff: "hard", topic: "Protocols", q: "What is SCTP (Stream Control Transmission Protocol) and what advantages does it offer over TCP?", opts: ["SCTP is identical to TCP but with UDP as its underlying transport", "SCTP supports multi-streaming (independent streams within one association, avoiding HOL blocking) and multi-homing (multiple IP endpoints per association for path failover)", "TCP is strictly more secure and reliable than SCTP in all network conditions", "SCTP is a faster but completely unreliable datagram protocol"], ans: 1, exp: "SCTP (RFC 4960): used in telecoms (SS7 over IP, Diameter). Multi-streaming: 16 independent streams per association â€” a stalled stream doesn't block others. Multi-homing: if one path fails, the association continues on another." },
  { id: "cn149", diff: "hard", topic: "Protocols", q: "How does OSPF prevent network instability from excessive LSA flooding?", opts: ["OSPF strictly limits LSAs to 10 per router per update cycle", "OSPF uses sequence numbers (duplicate detection), MaxAge (3600s to expire stale LSAs), MinLSInterval (5s minimum between refreshes), and area design to limit flooding scope", "OSPF drops all LSAs during congestion events to protect routing stability", "LSA flooding is handled by BGP, not by OSPF internally"], ans: 1, exp: "OSPF flooding controls: sequence numbers (ignore duplicates), 3600s MaxAge (stale LSA auto-expiry), MinLSInterval (5s between origin refreshes). Area design: Type 1/2 LSAs are area-scoped; ABRs/ASBRs summarize inter-area/external routes." },
  { id: "cn150", diff: "hard", topic: "Protocols", q: "What is the difference between distance-vector, link-state, and path-vector routing protocol classes?", opts: ["They are simply different names for the same underlying algorithm", "Distance-vector (RIP, EIGRP): share routing table with neighbors, prone to count-to-infinity. Link-state (OSPF, IS-IS): flood topology, build full map, run Dijkstra. Path-vector (BGP): share complete AS-path list, loop prevention via AS_PATH", "Link-state protocols use hop count; distance-vector protocols use Dijkstra's algorithm", "Path-vector routing is only used within local area networks and campus environments"], ans: 1, exp: "Distance-vector: 'routing by rumor' â€” only know what neighbors tell you. Converges slowly, loop-prone. Link-state: every router knows the full topology and independently computes optimal paths. Path-vector (BGP): exchanges the full list of ASes a route traverses â€” loop detection via AS_PATH, policy-rich routing." },
  { id: "cn151", diff: "scenario", topic: "Troubleshooting", q: "Scenario: A workstation randomly loses network connectivity for a few minutes and then regains it. A packet capture shows multiple Gratuitous ARP packets originating from a different MAC address claiming the IP address of the default gateway. What is happening?", opts: ["The network is experiencing a routing loop.", "An ARP spoofing/poisoning attack is in progress.", "The DHCP server lease time is too short.", "The default gateway router is rebooting."], ans: 1, exp: "Gratuitous ARPs are used to update MAC tables. An attacker sending them with the gateway's IP but their own MAC is performing ARP spoofing to intercept traffic (Man-in-the-Middle)." },
  { id: "cn152", diff: "scenario", topic: "Troubleshooting", q: "Scenario: Your company web server (HTTPS) suddenly becomes unreachable. You attempt to ping the server by its IP address and it responds successfully. You then try `curl -I https://<server-ip>` and receive a connection timeout. What is the most logical next step?", opts: ["Check the DNS configuration on the client.", "Check if the server's default gateway is down.", "Investigate the firewall rules to see if TCP port 443 is being blocked or if the web service has crashed.", "Check for a duplicate IP address on the network."], ans: 2, exp: "Ping (ICMP) succeeds, meaning Layer 3 routing is intact. The failure is at Layer 4/7 (HTTPS/Port 443), indicating a blocked port via firewall or a downed web service." },
  { id: "cn153", diff: "scenario", topic: "Troubleshooting", q: "Scenario: A user opens a browser and types www.example.com. The browser hangs for 10 seconds and then displays a 'Server not found' error. However, pinging 8.8.8.8 from the command line works perfectly. What is the root cause?", opts: ["The client's IP address has expired.", "The client's default gateway is misconfigured.", "The client's configured DNS server is unreachable or failing to resolve queries.", "The HTTP service on example.com is down."], ans: 2, exp: "Reaching 8.8.8.8 confirms Internet connectivity and routing. The failure to load a domain name points directly to a DNS resolution failure." },
  { id: "cn154", diff: "scenario", topic: "Routing", q: "Scenario: A developer complains that database queries from an app server to a DB server in a different subnet are extremely slow. You observe that ping between the two servers shows 0% packet loss but a consistent 150ms round-trip time. They are in the same local data center. What is a likely cause?", opts: ["The switch port is operating in half-duplex mode.", "The traffic is taking a suboptimal, asymmetric routing path through a distant WAN link.", "The MTU size on the database server is set too high.", "The application is experiencing HTTP head-of-line blocking."], ans: 1, exp: "Consistent high latency (150ms) within a local data center usually indicates that packets are being routed incorrectly through a distant network or firewall, often due to a routing loop or suboptimal static route." },
  { id: "cn155", diff: "scenario", topic: "Switching", q: "Scenario: You configure a new Cisco switch and connect it to an existing switch via a trunk port. Suddenly, the entire network goes down, and switch CPU utilization spikes to 100%. The link lights on all switches are blinking furiously. What did you likely forget to configure?", opts: ["Access Control Lists (ACLs)", "Spanning Tree Protocol (STP) safeguards or BPDU Guard", "Port Security", "802.1Q Encapsulation"], ans: 1, exp: "The symptoms describe a broadcast storm caused by a Layer 2 loop. If STP is misconfigured, disabled, or new links create loops without safeguards, broadcast traffic circulates endlessly, crashing the network." },
  { id: "cn156", diff: "scenario", topic: "Subnetting", q: "Scenario: A network engineer is designing a subnet for a new branch office that will have exactly 28 hosts. They want to conserve IP addresses. Which subnet mask provides just enough IP addresses for this requirement while leaving room for the network and broadcast addresses?", opts: ["255.255.255.224 (/27)", "255.255.255.240 (/28)", "255.255.255.248 (/29)", "255.255.255.192 (/26)"], ans: 0, exp: "28 hosts require at least 30 total IPs (including network and broadcast). A /27 subnet provides 32 total addresses (30 usable). A /28 only provides 14 usable IPs, which is insufficient." },
  { id: "cn157", diff: "scenario", topic: "Troubleshooting", q: "Scenario: Two routers, R1 and R2, are connected directly. R1 is configured with IP 10.0.0.1/30 and R2 with 10.0.0.2/30. R1 cannot ping R2. You check the interfaces and both are 'up/up'. R1's routing table shows the directly connected network. What could prevent the ping from succeeding?", opts: ["An ACL on R2 is dropping ICMP Echo Requests.", "The subnet mask on R2 is incorrectly set to /29.", "OSPF has not converged yet.", "The default gateway is missing on R1."], ans: 0, exp: "Since they are directly connected, on the same /30 subnet, and interfaces are up/up, routing protocols or default gateways are not needed. An ACL blocking ICMP or a firewall is the most likely culprit." },
  { id: "cn158", diff: "scenario", topic: "Congestion", q: "Scenario: During a performance test, an application transferring large files over TCP is only utilizing 10% of a 1 Gbps link with a 100ms latency. Packet loss is 0%. What tuning is required to improve throughput?", opts: ["Decrease the MTU size to prevent fragmentation.", "Increase the TCP window size (socket buffers) to match the Bandwidth-Delay Product (BDP).", "Switch the application transport protocol to UDP.", "Enable TCP Fast Retransmit."], ans: 1, exp: "On high-bandwidth, high-latency links, the default TCP receive window limits the amount of unacknowledged data in flight. Increasing the window size to match the BDP allows TCP to fully utilize the link." },
  { id: "cn159", diff: "scenario", topic: "TCP/IP", q: "Scenario: You are analyzing a packet capture of a failed TCP connection. You see a SYN packet from the client, a SYN-ACK from the server, an ACK from the client, and then an immediate RST (Reset) from the server. What is the most plausible explanation?", opts: ["The client's firewall blocked the connection.", "The server's application crashed or is not listening on that port after the OS accepted the handshake.", "The client sent the ACK with the wrong sequence number.", "A Man-in-the-Middle attacker is hijacking the session."], ans: 1, exp: "The OS kernel completed the 3-way handshake (SYN, SYN-ACK, ACK), but when the OS tried to pass the socket to the application, the app was unavailable or closed the socket, triggering an immediate RST." },
  { id: "cn160", diff: "scenario", topic: "Security", q: "Scenario: An employee uses an unencrypted public Wi-Fi network at a coffee shop. An attacker on the same network captures the employee's HTTP session cookie. The attacker injects the cookie into their own browser and accesses the employee's account. What type of attack is this, and how is it mitigated?", opts: ["Session Hijacking; Mitigated by using HTTPS and setting the 'Secure' flag on cookies.", "Cross-Site Scripting (XSS); Mitigated by input sanitization.", "ARP Spoofing; Mitigated by Dynamic ARP Inspection.", "CSRF; Mitigated by Anti-CSRF tokens."], ans: 0, exp: "Stealing a valid session token and reusing it is Session Hijacking. Enforcing HTTPS and using the 'Secure' attribute ensures cookies are never transmitted in plaintext over the network." },
  { id: "cn161", diff: "scenario", topic: "Congestion", q: "Scenario: Users report that voice calls (VoIP) over the corporate WAN are experiencing severe jitter and robotic voices during peak business hours. File transfers, however, work fine. How should the network administrator resolve this?", opts: ["Upgrade the link from IPv4 to IPv6.", "Implement Quality of Service (QoS) to prioritize UDP VoIP traffic (EF class) over bulk TCP traffic.", "Increase the TCP sliding window size on the voice servers.", "Switch the VoIP application to use TCP instead of UDP."], ans: 1, exp: "VoIP is sensitive to delay and jitter but uses UDP, which backs down to nothing when congested by TCP. QoS prioritizes the VoIP packets to ensure they traverse the WAN link without delay." },
  { id: "cn162", diff: "scenario", topic: "Security", q: "Scenario: Your web server is under a massive DDoS attack consisting of fragmented ICMP packets. You decide to block all ICMP traffic at the perimeter firewall. What is a negative side effect of this action?", opts: ["TCP connections will no longer be able to establish a 3-way handshake.", "Path MTU Discovery (PMTUD) will break, causing dropped packets for users with lower MTUs.", "DNS resolution for external domains will fail.", "ARP will stop functioning, bringing down the local network."], ans: 1, exp: "PMTUD relies on ICMP 'Fragmentation Needed' (Type 3, Code 4) messages. If all ICMP is blocked, routers cannot notify senders to lower their MTU, leading to silent drops of large packets (black hole connections)." },
  { id: "cn163", diff: "scenario", topic: "Routing", q: "Scenario: Look at the following routing table entry: 'O 192.168.10.0/24 [110/65] via 10.1.1.2, 00:15:32, GigabitEthernet0/1'. What does the '110' represent?", opts: ["The OSPF link cost (metric).", "The Administrative Distance (AD) for OSPF.", "The hop count to the destination.", "The autonomous system number."], ans: 1, exp: "In Cisco routing tables, '[Administrative Distance / Metric]'. 110 is the default AD for OSPF, meaning the router trusts it less than EIGRP (90) but more than RIP (120). 65 is the metric (cost)." },
  { id: "cn164", diff: "scenario", topic: "Troubleshooting", q: "Scenario: A user cannot access a specific secure website (https://internal.app.com). The browser shows a 'SEC_ERROR_UNKNOWN_ISSUER' or 'Certificate Authority Invalid' error. Other users on the same network do not have this issue. What is the cause?", opts: ["The web server's TLS certificate has expired.", "The user's computer is missing the internal Root CA certificate in its trusted root store.", "The network firewall is performing SSL inspection without properly resigning the traffic.", "The website is using a self-signed certificate that all other users ignored."], ans: 1, exp: "Since only one user has the issue, the server certificate is fine. The user's OS or browser lacks the Root CA (often distributed via Group Policy in enterprises) needed to establish the chain of trust." },
  { id: "cn165", diff: "scenario", topic: "App Layer", q: "Scenario: A company hosts a service on IP 203.0.113.5. They change ISPs and update the DNS A record to point to a new IP 198.51.100.10. An hour later, some external users still connect to the old IP, while others connect to the new IP. Why?", opts: ["The new ISP has not updated their BGP routes.", "The BGP route is flapping.", "DNS caching by intermediate resolvers and client OS based on the record's Time-To-Live (TTL).", "The old ISP is maliciously hijacking the DNS requests."], ans: 2, exp: "DNS records have a TTL. Intermediate DNS servers and client devices cache the old IP until the TTL expires. This is why DNS propagation for a change takes time." },
  { id: "cn166", diff: "scenario", topic: "Protocols", q: "Scenario: You capture a DHCP exchange: Discover, Offer, Request, but no Acknowledge (ACK). The client eventually gives up and self-assigns an APIPA (169.254.x.x) address. What could cause the server to drop the Request?", opts: ["The client requested an IP that is already in use by another device (IP conflict).", "The DHCP scope is completely exhausted.", "The DHCP relay agent is blocking unicast traffic.", "The client is on a different VLAN than the DHCP server."], ans: 0, exp: "If the scope were exhausted, the server wouldn't send an Offer. The server offered an IP, the client requested it, but before ACKing, the server likely did an ICMP ping check, found the IP was active on the network, and withheld the ACK." },
  { id: "cn167", diff: "scenario", topic: "App Layer", q: "Scenario: A developer implements an API using HTTP GET requests to transfer funds between user accounts. Security auditing flags this as a critical vulnerability. Why?", opts: ["GET requests cannot be encrypted by TLS.", "GET requests do not support HTTP headers.", "GET requests log parameters in browser history, proxy logs, and are highly vulnerable to Cross-Site Request Forgery (CSRF).", "GET requests are significantly slower than POST requests."], ans: 2, exp: "GET requests should be idempotent (safe, no side effects). Using GET for state-changing actions exposes parameters in URLs (logging) and allows attackers to trigger actions simply by making victims load an image tag." },
  { id: "cn168", diff: "scenario", topic: "Switching", q: "Scenario: An engineer connects two switches together using two separate cables to increase bandwidth. Instead of increasing bandwidth, the network becomes unusable. How can the engineer achieve the bandwidth increase without causing a loop?", opts: ["Disable Spanning Tree Protocol on both links.", "Configure PortFast on the connected interfaces.", "Configure an EtherChannel (Link Aggregation / LACP) across the two ports.", "Change the duplex mode to half-duplex on one link."], ans: 2, exp: "Connecting two switches with two cables creates a Layer 2 loop. STP will block one link, yielding no extra bandwidth. EtherChannel bundles multiple physical links into one logical link, providing load balancing and loop-free high bandwidth." },
  { id: "cn169", diff: "scenario", topic: "Routing", q: "Scenario: A host with IP 192.168.1.50/24 tries to send a packet to 192.168.2.50/24. What is the very first step the host takes before transmitting the packet?", opts: ["Sends an ARP request for the MAC address of 192.168.2.50.", "Compares the destination IP with its own subnet mask to determine if the destination is local or remote.", "Sends the packet directly out of its physical interface to the switch.", "Sends a DNS query to find the gateway's IP address."], ans: 1, exp: "A host always performs a logical AND operation using its IP and subnet mask, and the destination IP and subnet mask. If they don't match, it determines the destination is remote and must route the packet to its Default Gateway." },
  { id: "cn170", diff: "scenario", topic: "Security", q: "Scenario: You observe a network attack where an attacker sends a massive volume of ICMP Echo Requests to the broadcast address of a network, using a spoofed source IP belonging to the victim. The entire network then replies to the victim, overwhelming it. What is this attack called?", opts: ["Smurf Attack", "SYN Flood", "Ping of Death", "Teardrop Attack"], ans: 0, exp: "A Smurf attack is a classic reflection/amplification DDoS attack. By sending ICMP to a broadcast address with a spoofed source, all hosts on that subnet reply to the victim, multiplying the attacker's bandwidth." },
  { id: "cn171", diff: "scenario", topic: "Security", q: "Scenario: A company uses a stateless firewall. You create a rule: 'ALLOW INBOUND TCP PORT 80'. Internal users complain they cannot browse external websites. Why?", opts: ["You forgot to allow outbound TCP port 80.", "You forgot to allow inbound high ports (ephemeral ports) for the return traffic.", "Stateless firewalls cannot process HTTP traffic.", "The firewall is dropping DNS requests."], ans: 1, exp: "A stateless firewall evaluates each packet independently and doesn't track connections. If a user connects to port 80 externally, the return traffic comes back to a random ephemeral port (e.g., 45000) on the client. Without a rule allowing inbound ephemeral ports, the return traffic is dropped." },
  { id: "cn172", diff: "scenario", topic: "Routing", q: "Scenario: Your network uses BGP to connect to two different ISPs (Dual-homed). You want all outbound traffic to use ISP A, and only use ISP B if ISP A fails. Which BGP attribute should you modify for your outbound routes?", opts: ["AS_PATH", "Multi-Exit Discriminator (MED)", "Local Preference (LOCAL_PREF)", "Origin Code"], ans: 2, exp: "Local Preference is an iBGP attribute used to dictate how traffic leaves an Autonomous System. A higher Local Preference on routes learned from ISP A will ensure all outbound traffic prefers that path." },
  { id: "cn173", diff: "scenario", topic: "Security", q: "Scenario: A user connects to the company VPN. They can access internal corporate servers perfectly, but they completely lose access to the public Internet while connected. What VPN configuration is causing this?", opts: ["Split Tunneling is enabled.", "Full Tunneling is enabled (No Split Tunneling).", "The VPN is using an outdated IPsec protocol.", "The VPN client lacks administrator privileges."], ans: 1, exp: "Full Tunneling forces all client traffic, including generic Internet traffic, through the VPN tunnel to the corporate gateway. If the corporate gateway doesn't NAT/allow that traffic out to the internet, the user loses internet access." },
  { id: "cn174", diff: "scenario", topic: "Security", q: "Scenario: A monitoring tool alerts that an enterprise switch has a 'CAM table full' status. Immediately after, the switch begins acting like a hub, forwarding all unicast traffic out of all ports. What is likely occurring?", opts: ["A broadcast storm caused by an STP failure.", "A MAC flooding attack.", "A DHCP starvation attack.", "An oversized MTU attack."], ans: 1, exp: "A MAC flooding attack bombards the switch with thousands of fake source MAC addresses, exhausting the CAM table. Once full, the switch cannot learn new MACs and must broadcast all unknown unicast frames, allowing the attacker to sniff the traffic." },
  { id: "cn175", diff: "scenario", topic: "TCP/IP", q: "Scenario: Two devices are connected via a router. Device A sends a TCP segment with a sequence number of 1000 and a payload of 500 bytes. What acknowledgment number does Device A expect from Device B to confirm receipt?", opts: ["1000", "1001", "1500", "1501"], ans: 2, exp: "TCP Acknowledgments are cumulative and indicate the next expected byte. Sequence 1000 + 500 bytes of data = bytes 1000 through 1499. The next expected byte is 1500." },
  { id: "cn176", diff: "scenario", topic: "App Layer", q: "Scenario: You manage a web application behind a load balancer. The application servers log the source IP of all incoming requests. However, the logs show that every single request comes from the load balancer's internal IP. How do you fix this to log the actual client IPs?", opts: ["Change the load balancer from Layer 7 to Layer 4 (DSR) or configure it to insert the X-Forwarded-For HTTP header.", "Enable NAT on the application servers.", "Configure the application to read the MAC address of the client.", "Use HTTPS instead of HTTP."], ans: 0, exp: "A Layer 7 reverse proxy terminates the TCP connection and opens a new one to the backend, masking the client IP. The standard solution is to append the X-Forwarded-For header, which the backend reads, or use a Layer 4 load balancer with Direct Server Return (DSR)." },
  { id: "cn177", diff: "scenario", topic: "Security", q: "Scenario: During an incident response, you find a compromised server communicating with an external C2 server. The traffic is fully encrypted, but you notice the server is making DNS requests for randomly generated, very long domain names (e.g., a1b2c3d4e5.attacker.com). What technique is the malware using?", opts: ["DNS Amplification", "DNS Cache Poisoning", "DNS Tunneling / Exfiltration", "DNS Spoofing"], ans: 2, exp: "Malware often uses DNS Tunneling to bypass firewalls that allow outbound DNS (port 53). It encodes stolen data into the subdomain portion of a query. The attacker's authoritative name server receives the query, decodes the data, and can even send commands back via DNS TXT records." },
  { id: "cn178", diff: "scenario", topic: "Switching", q: "Scenario: An engineer configures a new VLAN 50 on two switches connected by an 802.1Q trunk. However, hosts on VLAN 50 on Switch A cannot communicate with hosts on VLAN 50 on Switch B. Other VLANs on the trunk work fine. What is the most likely cause?", opts: ["The trunk link is down.", "VLAN 50 is not permitted on the trunk's allowed VLAN list.", "Spanning Tree is disabled.", "The hosts are not configured with default gateways."], ans: 1, exp: "If other VLANs work across the trunk, the physical link and trunking protocol are functioning. The specific VLAN must be missing from the 'switchport trunk allowed vlan' configuration on one or both switches." },
  { id: "cn179", diff: "scenario", topic: "Subnetting", q: "Scenario: A company uses a /24 subnet for their office network. They have exactly 200 devices. They notice extreme network sluggishness. Packet captures show a massive amount of ARP requests constantly flooding the network. What is the best architectural solution?", opts: ["Upgrade the switch uplink ports from 1Gbps to 10Gbps.", "Implement VLANs to segment the network into smaller broadcast domains.", "Change the subnet mask to /16.", "Disable ARP and use static MAC addresses."], ans: 1, exp: "ARP requests are broadcast traffic. A single /24 with 200 devices can generate significant broadcast noise. Segmenting the network into multiple VLANs breaks up the broadcast domain, significantly reducing overhead." },
  { id: "cn180", diff: "scenario", topic: "Security", q: "Scenario: An attacker intercepts a legitimate user's successful authentication response from a server and saves it. Later, the attacker sends this exact same response back to the server to gain unauthorized access. The server accepts it. What vulnerability allowed this, and how is it fixed?", opts: ["SQL Injection; fixed by prepared statements.", "Replay Attack; fixed by implementing nonces, timestamps, or sequence numbers.", "Cross-Site Scripting; fixed by CSP.", "Downgrade Attack; fixed by TLS 1.3."], ans: 1, exp: "Replaying a captured authentication token/message is a Replay Attack. To prevent it, protocols include a unique, one-time value (nonce), a timestamp, or an incrementing sequence number (like in IPsec) to ensure messages cannot be reused." }
,
  { id: "cn181", diff: "scenario", topic: "Routing", q: "Scenario (Image Based): Observe the network topology diagram below. PC1 wants to communicate with the Server. If Switch A fails completely, what will happen to the communication between PC1 and the Server?", opts: ["Communication continues seamlessly because the Router provides a backup path.", "Communication drops entirely because PC1 has no alternate physical path to reach the Router.", "Switch B will automatically take over Switch A's forwarding table.", "The Server will initiate a connection directly to PC1 to bypass the failure."], ans: 1, exp: "In this simple tree topology, Switch A acts as a single point of failure for PC1 and PC2. Without redundant links (like a secondary path to another switch or router), the physical connection is broken and communication drops.", image: "/images/network_topology_1.png" },
  { id: "cn182", diff: "scenario", topic: "Security", q: "Scenario (Image Based): Observe the firewall network diagram. The public-facing Web Server is placed in the DMZ, while the Database Server is in the Internal Network. Why is this tiered architecture more secure than placing both servers in the Internal Network?", opts: ["It automatically encrypts the database traffic.", "If the Web Server is compromised, the attacker must still bypass another layer of firewall rules to reach the Database Server.", "It prevents external users from accessing the Web Server directly over the Internet.", "It allows the Web Server to bypass the firewall completely for faster HTTP performance."], ans: 1, exp: "A DMZ provides an isolated subnet for untrusted, public-facing servers. If the Web Server is hacked, the attacker is contained within the DMZ and cannot automatically pivot to the sensitive Database Server without breaching the internal firewall rules.", image: "/images/network_firewall_diagram.png" },

  { id: "cn183", diff: "easy", topic: "Network Topologies", q: "In a full mesh topology with 6 devices, how many physical links are required to connect all devices directly to each other?", opts: ["6", "10", "15", "36"], ans: 2, exp: "The formula for the number of links in a full mesh network is n(n-1)/2. For 6 devices: 6(5)/2 = 30/2 = 15 links." },
  { id: "cn184", diff: "easy", topic: "Network Topologies", q: "Which of the following is the primary disadvantage of a traditional Bus topology?", opts: ["It requires the most cabling of any topology.", "A single cable break brings down the entire network segment.", "It is highly complex to configure.", "It requires a central intelligent switch to operate."], ans: 1, exp: "In a bus topology, all devices share a single backbone cable. If that cable is cut or improperly terminated, the entire network fails due to signal reflection." },
  { id: "cn185", diff: "medium", topic: "Network Topologies", q: "Scenario: A company uses a Token Ring topology. Device A wants to send data to Device C but does not currently have the token. What must Device A do?", opts: ["Broadcast a token request to all devices.", "Wait until the circulating token is passed to it, attach the data, and send it back onto the ring.", "Send the data immediately with a high-priority flag.", "Send the data directly to the central switch."], ans: 1, exp: "In a Token Ring network, a device can only transmit data when it possesses the token. It must wait for the token to arrive, modify it to a 'data' frame, attach its payload, and pass it along." },
  { id: "cn186", diff: "medium", topic: "Network Topologies", q: "What is the primary advantage of a Star topology compared to a Bus or Ring topology?", opts: ["It uses significantly less cable.", "A cable failure only affects the specific device connected to it, not the entire network.", "It eliminates the need for central networking equipment.", "It provides higher data encryption by default."], ans: 1, exp: "In a star topology, each node connects to a central device (switch/hub). If one node's cable fails, only that node loses connectivity. The rest of the network continues to operate normally." },
  { id: "cn187", diff: "hard", topic: "Network Topologies", q: "Modern data centers have largely shifted away from the traditional 3-tier architecture (Core, Distribution, Access) in favor of which topology?", opts: ["Full Mesh", "Spine-Leaf", "Token Ring", "Extended Star"], ans: 1, exp: "Spine-Leaf (Clos network) topology provides highly predictable, low-latency east-west traffic flow. Every leaf switch connects to every spine switch, ensuring every server is exactly the same number of hops away from any other server." },
  { id: "cn188", diff: "medium", topic: "Network Topologies", q: "What defines a Hybrid topology?", opts: ["A topology that uses both IPv4 and IPv6.", "A combination of two or more different basic topologies, such as a Star-Bus or Star-Ring.", "A network that uses both wired and wireless connections.", "A topology that uses both fiber optic and copper cabling."], ans: 1, exp: "A hybrid topology integrates multiple distinct topologies. For example, a Star-Bus topology consists of multiple star networks connected by a single bus backbone." },
  { id: "cn189", diff: "scenario", topic: "Network Topologies", q: "Scenario: An enterprise is migrating from a traditional WAN to SD-WAN. They are decoupling the control plane from the data plane. In this context, the physical circuits (MPLS, Broadband, LTE) are referred to as what?", opts: ["The Overlay Network", "The Underlay Network", "The Control Plane", "The Management Plane"], ans: 1, exp: "In SD-WAN, the physical transport links (MPLS, Internet, LTE) form the 'Underlay'. The 'Overlay' is the logical, encrypted virtual network (often IPsec tunnels) built on top of the underlay." },
  { id: "cn190", diff: "scenario", topic: "Network Topologies", q: "Scenario: You are designing a campus network using the Cisco 3-tier hierarchical model. At which layer should you implement high-speed routing, avoiding complex QoS or security policies to maximize packet forwarding speed?", opts: ["Access Layer", "Distribution Layer", "Core Layer", "Perimeter Layer"], ans: 2, exp: "The Core Layer is the high-speed backbone. Its sole purpose is to switch packets as fast as possible. Complex policies (routing boundaries, filtering, QoS) should be handled at the Distribution Layer." }
];

